const data = [
  // ── COLONIAL ──
  { name:"John Smith", dates:"1580–1631", era:"Colonial", tags:["explorer","leader"], desc:"English soldier and explorer who helped establish Jamestown in 1607, the first permanent English settlement in North America. His leadership and insistence that colonists work to eat arguably saved the colony from collapse." },
  { name:"Pocahontas (Amonute)", dates:"c.1596–1617", era:"Colonial", tags:["Native American","diplomat"], desc:"Powhatan chief's daughter whose relationship with English colonists at Jamestown became legendary; later baptized and married John Rolfe, traveling to England where she died." },
  { name:"John Rolfe", dates:"1585–1622", era:"Colonial", tags:["entrepreneur"], desc:"Pioneered the cultivation of tobacco in Virginia, creating the cash crop that made the Chesapeake colonies economically viable." },
  { name:"Powhatan (Wahunsenaca)", dates:"c.1547–1618", era:"Colonial", tags:["Native American","leader"], desc:"Paramount chief of the Powhatan Confederacy who controlled much of tidewater Virginia; initially maintained ambiguous relations with English settlers at Jamestown." },
  { name:"Anne Hutchinson", dates:"1591–1643", era:"Colonial", tags:["religious","women"], desc:"Puritan religious leader in Massachusetts Bay Colony who challenged clerical authority by holding home meetings where she reinterpreted sermons. Banished in 1638 for antinomianism, she fled to Rhode Island and later New York, where she was killed in a Native American raid." },
  { name:"Roger Williams", dates:"1603–1683", era:"Colonial", tags:["religious","leader"], desc:"Puritan minister banished from Massachusetts Bay for advocating separation of church and state and fair treatment of Native Americans. Founded Providence, Rhode Island in 1636, establishing one of the earliest experiments in religious toleration in the Americas." },
  { name:"John Winthrop", dates:"1588–1649", era:"Colonial", tags:["leader","Puritan"], desc:"First governor of Massachusetts Bay Colony and dominant Puritan leader of early New England. His 'city upon a hill' vision defined Puritan New England's sense of divine mission and shaped American exceptionalism as a concept." },
  { name:"William Penn", dates:"1644–1718", era:"Colonial", tags:["Quaker","founder"], desc:"Quaker leader who founded Pennsylvania in 1681 as a 'holy experiment' in religious tolerance. Maintained notably peaceful relations with the Lenape people and established Philadelphia as a planned city and commercial hub." },
  { name:"Peter Stuyvesant", dates:"1612–1672", era:"Colonial", tags:["leader"], desc:"Last Dutch Director-General of New Netherland who reluctantly surrendered the colony to England in 1664; known for his peg leg and authoritarian rule." },
  { name:"Nathaniel Bacon", dates:"1647–1676", era:"Colonial", tags:["rebel"], desc:"Led Bacon's Rebellion in 1676, an armed uprising of frontier settlers, servants, and formerly enslaved people against Virginia's Governor Berkeley. Though crushed, it alarmed planters and accelerated the shift toward African slavery over indentured servitude." },
  { name:"William Berkeley", dates:"1605–1677", era:"Colonial", tags:["governor"], desc:"Royal Governor of Virginia whose favoritism toward the tidewater elite and refusal to protect frontier settlers sparked Bacon's Rebellion." },
  { name:"Metacom (King Philip)", dates:"c.1638–1676", era:"Colonial", tags:["Native American","leader"], desc:"Wampanoag leader who organized King Philip's War (1675–76), the most devastating colonial conflict in New England proportionally, killing thousands on both sides before his death ended Native resistance in the region." },
  { name:"Cotton Mather", dates:"1663–1728", era:"Colonial", tags:["religious","Puritan"], desc:"Influential Puritan minister whose writings on witchcraft contributed to the Salem Witch Trials hysteria; also wrote on science and promoted smallpox inoculation." },
  { name:"Tituba", dates:"c.1650s–?", era:"Colonial", tags:["enslaved"], desc:"Enslaved woman in Salem whose confession of witchcraft helped ignite the Salem Witch Trials hysteria of 1692." },
  { name:"John Peter Zenger", dates:"1697–1746", era:"Colonial", tags:["press","free speech"], desc:"German-born printer whose 1735 acquittal on seditious libel charges established an early precedent for freedom of the press and truth as a defense against libel." },
  { name:"Olaudah Equiano", dates:"c.1745–1797", era:"Colonial", tags:["abolitionist","enslaved"], desc:"Formerly enslaved African whose 1789 autobiography became a landmark abolitionist text, graphically depicting the Middle Passage and arguing for the humanity of enslaved people." },
  { name:"Eliza Lucas Pinckney", dates:"1722–1793", era:"Colonial", tags:["women","entrepreneur"], desc:"Pioneered indigo cultivation in South Carolina in the 1740s, creating a profitable export crop that transformed the colony's economy." },
  { name:"Pontiac", dates:"c.1720–1769", era:"Colonial", tags:["Native American","leader"], desc:"Ottawa war leader who organized Pontiac's Rebellion (1763) against British forts in the Great Lakes region following the French and Indian War, leading to the Proclamation of 1763." },
  { name:"James Oglethorpe", dates:"1696–1785", era:"Colonial", tags:["founder"], desc:"Founded the colony of Georgia in 1733 as a haven for debtors and a buffer against Spanish Florida; banned slavery in Georgia initially." },
  { name:"Jonathan Edwards", dates:"1703–1758", era:"Colonial", tags:["religious"], desc:"Puritan theologian and revivalist preacher whose hellfire sermons like 'Sinners in the Hands of an Angry God' ignited the First Great Awakening of the 1730s–40s." },
  { name:"George Whitefield", dates:"1714–1770", era:"Colonial", tags:["religious"], desc:"Charismatic itinerant British minister who toured the colonies multiple times, drawing massive crowds and catalyzing the First Great Awakening across denominational lines." },
  { name:"John Locke", dates:"1632–1704", era:"Colonial", tags:["philosopher"], desc:"English philosopher whose ideas on natural rights, consent of the governed, and social contract theory directly influenced the Declaration of Independence and American founding ideology." },
  { name:"William Bradford", dates:"1590–1657", era:"Colonial", tags:["leader","Puritan"], desc:"Leader of the Plymouth Colony Pilgrims and governor for 30+ years; authored 'Of Plymouth Plantation,' the primary account of the Mayflower voyage and early colony life." },
  { name:"Massasoit", dates:"c.1581–1661", era:"Colonial", tags:["Native American","leader"], desc:"Wampanoag sachem who forged a peace treaty with the Plymouth colonists in 1621 that held for 50 years, enabling the survival of the Plymouth Colony." },
  { name:"John Cabot", dates:"c.1450–1500", era:"Colonial", tags:["explorer"], desc:"Italian explorer sailing for England who reached North America in 1497, establishing English claims to the continent that would eventually justify colonial settlement." },
  { name:"Samuel de Champlain", dates:"1574–1635", era:"Colonial", tags:["explorer","French"], desc:"French explorer who founded Quebec City in 1608 and mapped much of northeastern North America, establishing France's enduring presence in the Great Lakes and St. Lawrence regions." },

  // ── REVOLUTION ──
  { name:"George Washington", dates:"1732–1799", era:"Revolution", tags:["Founding Father","president","military"], desc:"Commander-in-Chief of the Continental Army during the Revolutionary War, presiding over key victories at Trenton and Yorktown. As the first President (1789–97), he established foundational precedents — two-term limit, cabinet government, neutrality in foreign affairs — and is widely called the 'Father of His Country.'" },
  { name:"John Adams", dates:"1735–1826", era:"Revolution", tags:["Founding Father","president"], desc:"Boston lawyer, delegate to the Continental Congress, and advocate for independence who helped negotiate the Treaty of Paris (1783). As second President, he navigated the XYZ Affair, signed the Alien and Sedition Acts, and kept the nation out of full-scale war with France despite immense pressure from his own party." },
  { name:"Thomas Jefferson", dates:"1743–1826", era:"Revolution", tags:["Founding Father","president"], desc:"Principal author of the Declaration of Independence and architect of Virginia's Statute for Religious Freedom. As third President, he completed the Louisiana Purchase (1803), doubling the nation's size, and oversaw the Lewis and Clark Expedition — all while paradoxically enslaving over 600 people throughout his lifetime." },
  { name:"Benjamin Franklin", dates:"1706–1790", era:"Revolution", tags:["Founding Father","diplomat","scientist"], desc:"Printer, scientist, author, inventor, and diplomat who secured the French alliance critical to American victory in the Revolution. He helped draft the Declaration of Independence, the Constitution, and the Treaty of Paris — making him the only Founder to sign all four of the nation's key founding documents." },
  { name:"Alexander Hamilton", dates:"1755–1804", era:"Revolution", tags:["Founding Father","economist"], desc:"Washington's aide-de-camp, co-author of The Federalist Papers, and first Secretary of the Treasury. His financial program — national bank, assumption of state debts, excise taxes, protective tariffs — created America's capitalist economic foundation and established the Federalist vision of a strong national government." },
  { name:"James Madison", dates:"1751–1836", era:"Revolution", tags:["Founding Father","president"], desc:"'Father of the Constitution' who drafted the Virginia Plan, shepherded the Bill of Rights through Congress, and co-authored The Federalist Papers. As fourth President, he led the nation through the War of 1812, earning mixed reviews for the burning of Washington and eventual negotiated peace." },
  { name:"Patrick Henry", dates:"1736–1799", era:"Revolution", tags:["orator","patriot"], desc:"Virginia orator whose 'Give me liberty or give me death!' speech galvanized colonial resistance. A leading Anti-Federalist, he opposed ratification of the Constitution for lacking a Bill of Rights." },
  { name:"Samuel Adams", dates:"1722–1803", era:"Revolution", tags:["patriot","organizer"], desc:"Boston agitator and master political organizer who founded the Sons of Liberty, helped organize the Boston Tea Party, and kept colonial resistance networks alive through the Committees of Correspondence." },
  { name:"Thomas Paine", dates:"1737–1809", era:"Revolution", tags:["writer","patriot"], desc:"Radical English-American pamphleteer whose 'Common Sense' (1776) made the case for complete independence in plain language accessible to ordinary colonists, and whose 'The Crisis' papers sustained morale during the darkest days of the war." },
  { name:"Benedict Arnold", dates:"1741–1801", era:"Revolution", tags:["military","traitor"], desc:"Brilliant Continental Army general whose victories at Fort Ticonderoga and Saratoga were crucial to the Revolution, but who later defected to the British in 1780, becoming history's most famous American traitor." },
  { name:"Marquis de Lafayette", dates:"1757–1834", era:"Revolution", tags:["military","French"], desc:"French aristocrat and general who volunteered to serve Washington without pay, becoming one of his most trusted commanders and helping secure French military support for the American cause." },
  { name:"Baron von Steuben", dates:"1730–1794", era:"Revolution", tags:["military","Prussian"], desc:"Prussian military officer who drilled and trained the Continental Army at Valley Forge, transforming ragged troops into a disciplined fighting force." },
  { name:"Abigail Adams", dates:"1744–1818", era:"Revolution", tags:["women","Founding Mother"], desc:"Wife of John Adams whose 'Remember the Ladies' letter urged the Founders to include women's rights in the new laws; one of the most intellectually influential women of the founding era, often serving as her husband's closest political advisor." },
  { name:"Mercy Otis Warren", dates:"1728–1814", era:"Revolution", tags:["women","writer"], desc:"Patriot playwright and satirist whose anti-British plays helped mobilize colonial opinion; later wrote a major three-volume history of the American Revolution." },
  { name:"Crispus Attucks", dates:"c.1723–1770", era:"Revolution", tags:["patriot","Black American"], desc:"Mixed-race dockworker who was the first person killed in the Boston Massacre (1770), becoming an early martyr of the patriot cause." },
  { name:"Phillis Wheatley", dates:"c.1753–1784", era:"Revolution", tags:["poet","enslaved","Black American"], desc:"Enslaved African-born woman who became the first Black American to publish a book of poetry (1773), corresponding with George Washington and using her work to argue for both American freedom and the abolition of slavery." },
  { name:"James Armistead Lafayette", dates:"c.1748–1830", era:"Revolution", tags:["spy","Black American","enslaved"], desc:"Enslaved Black American who served as a double agent for the Continental Army, feeding British General Cornwallis false information in the lead-up to Yorktown." },
  { name:"John Jay", dates:"1745–1829", era:"Revolution", tags:["Founding Father","diplomat"], desc:"Co-author of The Federalist Papers, lead negotiator of the Treaty of Paris, and first Chief Justice of the Supreme Court." },
  { name:"Charles Cornwallis", dates:"1738–1805", era:"Revolution", tags:["British","military"], desc:"British general whose surrender at Yorktown in October 1781 effectively ended the Revolutionary War." },
  { name:"King George III", dates:"1738–1820", era:"Revolution", tags:["British","monarch"], desc:"British king whose policies — Stamp Act, Intolerable Acts, refusal to address colonial grievances — are blamed in the Declaration of Independence for tyranny, though Parliament drove most colonial policy." },
  { name:"George Mason", dates:"1725–1792", era:"Revolution", tags:["Founding Father","states rights"], desc:"Virginia statesman who authored the Virginia Declaration of Rights (1776), a model for the U.S. Bill of Rights; refused to sign the Constitution over its failure to abolish slavery and lack of a bill of rights." },
  { name:"Haym Salomon", dates:"1740–1785", era:"Revolution", tags:["financier"], desc:"Polish-Jewish broker who helped finance the Continental Army by raising funds in Europe and personally lending large sums to government officials." },

  // ── EARLY REPUBLIC ──
  { name:"John Marshall", dates:"1755–1835", era:"Early Republic", tags:["judiciary","Federalist"], desc:"Fourth and longest-serving Chief Justice whose landmark decisions — Marbury v. Madison (judicial review), McCulloch v. Maryland (implied powers), Gibbons v. Ogden (commerce clause) — established the judiciary as a co-equal branch and expanded federal power." },
  { name:"Aaron Burr", dates:"1756–1836", era:"Early Republic", tags:["politician","VP"], desc:"Third Vice President who killed Alexander Hamilton in an 1804 duel; later tried for treason for an alleged scheme to carve out a western empire, though acquitted." },
  { name:"Meriwether Lewis", dates:"1774–1809", era:"Early Republic", tags:["explorer"], desc:"Led the Corps of Discovery (1804–06) with William Clark, mapping Louisiana Territory, establishing U.S. claims to the Pacific Northwest, and returning with invaluable scientific and geographic data." },
  { name:"William Clark", dates:"1770–1838", era:"Early Republic", tags:["explorer"], desc:"Co-led the Lewis and Clark Expedition and later served as Superintendent of Indian Affairs, overseeing early U.S. policy toward Great Plains tribes." },
  { name:"Sacagawea", dates:"c.1788–1812", era:"Early Republic", tags:["Native American","explorer"], desc:"Shoshone woman who served as interpreter and guide for the Lewis and Clark Expedition; her presence signaled peaceful intentions and helped the Corps navigate Western tribes." },
  { name:"Tecumseh", dates:"1768–1813", era:"Early Republic", tags:["Native American","leader"], desc:"Shawnee leader who forged a pan-tribal confederacy to resist American westward expansion, allying with the British during the War of 1812. His death at the Battle of the Thames (1813) ended the most significant Native resistance movement east of the Mississippi." },
  { name:"Andrew Jackson", dates:"1767–1845", era:"Early Republic", tags:["president","military"], desc:"Hero of the Battle of New Orleans (1815), seventh President (1829–37), and founder of the Democratic Party. His presidency reshaped democracy — expanding white male suffrage, destroying the Second Bank, and institutionalizing the spoils system — while enacting the devastating Indian Removal Act and Trail of Tears." },
  { name:"John C. Calhoun", dates:"1782–1850", era:"Early Republic", tags:["politician","states rights"], desc:"South Carolina senator, Secretary of War, and Vice President whose doctrine of nullification — states' right to void federal law — nearly broke the Union in 1832 and provided theoretical foundation for secession in 1861." },
  { name:"Henry Clay", dates:"1777–1852", era:"Early Republic", tags:["politician","Whig"], desc:"'The Great Compromiser' whose Missouri Compromise (1820), Compromise Tariff (1833), and Compromise of 1850 delayed the Civil War for decades. Advocate of the 'American System' — protective tariffs, national bank, internal improvements." },
  { name:"Daniel Webster", dates:"1782–1852", era:"Early Republic", tags:["orator","politician"], desc:"Massachusetts senator and towering orator who championed nationalism and the Union above sectional interests; argued many landmark Supreme Court cases." },
  { name:"James Monroe", dates:"1758–1831", era:"Early Republic", tags:["president"], desc:"Fifth President whose 'Era of Good Feelings' masked growing sectional tensions; issued the Monroe Doctrine (1823) declaring the Western Hemisphere closed to further European colonization." },
  { name:"Sequoyah", dates:"c.1770–1843", era:"Early Republic", tags:["Native American","intellectual"], desc:"Cherokee polymath who single-handedly created a syllabary for the Cherokee language, enabling widespread literacy among his people within years of its introduction." },
  { name:"John Quincy Adams", dates:"1767–1848", era:"Early Republic", tags:["president","diplomat"], desc:"Sixth President and brilliant diplomat who co-authored the Monroe Doctrine; after his presidency, served in Congress as a fierce anti-slavery advocate and successfully argued the Amistad case." },
  { name:"Francis Scott Key", dates:"1779–1843", era:"Early Republic", tags:["poet"], desc:"Wrote 'The Star-Spangled Banner' after witnessing the British bombardment of Fort McHenry during the War of 1812." },
  { name:"Noah Webster", dates:"1758–1843", era:"Early Republic", tags:["intellectual","education"], desc:"Authored the first American dictionary and standardized American spelling, contributing to a distinct national cultural identity." },
  { name:"DeWitt Clinton", dates:"1769–1828", era:"Early Republic", tags:["politician","infrastructure"], desc:"Governor of New York who championed and oversaw construction of the Erie Canal (1825), transforming commerce in the Northeast and making New York City the nation's leading port." },
  { name:"Toussaint Louverture", dates:"1743–1803", era:"Early Republic", tags:["leader","revolution"], desc:"Leader of the Haitian Revolution whose success defeating Napoleon's forces contributed to France selling Louisiana, doubling U.S. territory. The revolution also frightened American slaveholders." },
  { name:"Albert Gallatin", dates:"1761–1849", era:"Early Republic", tags:["government","economist"], desc:"Swiss-born Secretary of the Treasury under Jefferson and Madison who substantially reduced the national debt; also helped negotiate the Treaty of Ghent ending the War of 1812." },

  // ── ANTEBELLUM ──
  { name:"Frederick Douglass", dates:"1818–1895", era:"Antebellum", tags:["abolitionist","orator","Black American"], desc:"Escaped enslaved man whose autobiography became the most powerful antislavery text of the 19th century. A magnetic orator, editor of the North Star newspaper, and advisor to Lincoln, Douglass pushed the nation toward emancipation and later championed Reconstruction and women's suffrage." },
  { name:"Harriet Tubman", dates:"c.1822–1913", era:"Antebellum", tags:["abolitionist","activist","Black American","women"], desc:"Escaped enslaved woman who made 13 missions back into slave territory as a 'conductor' on the Underground Railroad, rescuing approximately 70 people. During the Civil War she served as a spy, scout, and nurse for the Union Army." },
  { name:"William Lloyd Garrison", dates:"1805–1879", era:"Antebellum", tags:["abolitionist"], desc:"Radical white abolitionist who founded The Liberator newspaper and the American Anti-Slavery Society, demanding immediate, unconditional emancipation. His uncompromising rhetoric defined the moral stakes of the slavery debate." },
  { name:"Harriet Beecher Stowe", dates:"1811–1896", era:"Antebellum", tags:["writer","abolitionist","women"], desc:"Author of 'Uncle Tom's Cabin' (1852), the bestselling novel that humanized enslaved people for Northern white readers and inflamed antislavery sentiment. Lincoln reportedly called her 'the little woman who wrote the book that started this great war.'" },
  { name:"Sojourner Truth", dates:"c.1797–1883", era:"Antebellum", tags:["abolitionist","women's rights","Black American"], desc:"Formerly enslaved woman who became a powerful itinerant preacher, abolitionist, and women's rights advocate. Her 1851 'Ain't I a Woman?' speech forced the movement to grapple with the intersection of race and gender." },
  { name:"John Brown", dates:"1800–1859", era:"Antebellum", tags:["abolitionist","radical"], desc:"Radical white abolitionist who believed God commanded him to use violence to end slavery. He led the Pottawatomie Massacre in Kansas (1856) and his 1859 raid on Harpers Ferry — aimed at sparking a slave rebellion — panicked the South and accelerated the road to secession." },
  { name:"Nat Turner", dates:"1800–1831", era:"Antebellum", tags:["enslaved","rebellion","Black American"], desc:"Enslaved Virginia preacher who led the most significant slave rebellion in U.S. history in 1831, killing 55 white people before being captured and executed. The rebellion led to brutal reprisals and harsher slave codes across the South." },
  { name:"Elizabeth Cady Stanton", dates:"1815–1902", era:"Antebellum", tags:["women's rights","activist"], desc:"Primary organizer of the Seneca Falls Convention (1848) and author of the 'Declaration of Sentiments' which demanded equal rights for women including suffrage. Co-founded the National Woman Suffrage Association with Susan B. Anthony." },
  { name:"Susan B. Anthony", dates:"1820–1906", era:"Antebellum", tags:["women's rights","activist"], desc:"Tireless organizer of the suffrage movement who was famously arrested for voting in 1872. She co-founded the National Woman Suffrage Association and built the organizational infrastructure that led to the 19th Amendment — ratified 14 years after her death." },
  { name:"Dorothea Dix", dates:"1802–1887", era:"Antebellum", tags:["reformer","women"], desc:"Mental health reformer who investigated appalling conditions in prisons and almshouses and successfully lobbied state legislatures to build 32 mental hospitals; served as Superintendent of Army Nurses during the Civil War." },
  { name:"Horace Mann", dates:"1796–1859", era:"Antebellum", tags:["education","reformer"], desc:"Secretary of the Massachusetts Board of Education who established the first state-funded teacher training schools and promoted free public education, earning the title 'Father of American Education.'" },
  { name:"Ralph Waldo Emerson", dates:"1803–1882", era:"Antebellum", tags:["intellectual","Transcendentalist"], desc:"Philosopher, essayist, and poet who founded the Transcendentalist movement, emphasizing individualism, self-reliance, and the divinity of nature; his essays profoundly influenced American intellectual life and reform movements." },
  { name:"Henry David Thoreau", dates:"1817–1862", era:"Antebellum", tags:["intellectual","activist","Transcendentalist"], desc:"Author of 'Walden' and 'Civil Disobedience,' who argued that individuals must refuse to comply with unjust laws. His theories of nonviolent resistance directly influenced Gandhi and Martin Luther King Jr." },
  { name:"James K. Polk", dates:"1795–1849", era:"Antebellum", tags:["president"], desc:"Eleventh President who achieved all his expansionist goals — annexed Texas, settled the Oregon boundary, and won the Mexican-American War — acquiring California and the Southwest, but his acquisitions reignited the slavery crisis." },
  { name:"Stephen Douglas", dates:"1813–1861", era:"Antebellum", tags:["politician","Democrat"], desc:"Illinois senator who authored the Kansas-Nebraska Act, championed 'popular sovereignty,' and debated Lincoln in the famous 1858 Lincoln-Douglas debates; the Democratic Party split over his nomination in 1860, enabling Lincoln's election." },
  { name:"Roger Taney", dates:"1777–1864", era:"Antebellum", tags:["judiciary"], desc:"Chief Justice who wrote the disastrous Dred Scott v. Sandford decision (1857), ruling that Black Americans could never be citizens and that Congress had no power to restrict slavery in territories." },
  { name:"Dred Scott", dates:"c.1799–1858", era:"Antebellum", tags:["enslaved","Black American"], desc:"Enslaved man who sued for his freedom on the grounds that he had lived in free territories; the Supreme Court's ruling against him in 1857 became one of the most consequential and reviled decisions in judicial history." },
  { name:"Sam Houston", dates:"1793–1863", era:"Antebellum", tags:["leader","Texas"], desc:"Hero of the Texas Revolution, first President of the Republic of Texas, and later senator and governor; one of only two governors in U.S. history removed from office for refusing to swear loyalty to the Confederacy." },
  { name:"Samuel Morse", dates:"1791–1872", era:"Antebellum", tags:["inventor"], desc:"Invented the electromagnetic telegraph and Morse code, revolutionizing long-distance communication and shrinking the effective size of the United States." },
  { name:"Eli Whitney", dates:"1765–1825", era:"Antebellum", tags:["inventor","entrepreneur"], desc:"Invented the cotton gin (1793), which exponentially increased cotton production, dramatically expanded slavery in the Deep South, and ultimately pushed the nation toward Civil War; also pioneered interchangeable parts in manufacturing." },
  { name:"Cyrus McCormick", dates:"1809–1884", era:"Antebellum", tags:["inventor","entrepreneur"], desc:"Invented the mechanical reaper, revolutionizing grain harvesting and enabling vast expansion of Midwestern wheat farming." },
  { name:"Alexis de Tocqueville", dates:"1805–1859", era:"Antebellum", tags:["intellectual","French"], desc:"French political thinker whose 'Democracy in America' (1835) offered the most penetrating early analysis of American democracy, warning of the 'tyranny of the majority.'" },
  { name:"Angelina & Sarah Grimké", dates:"1805–1879 / 1792–1873", era:"Antebellum", tags:["abolitionist","women's rights"], desc:"South Carolina sisters from a slaveholding family who became the first women to testify before a U.S. legislature, linking abolitionism to women's rights in powerfully argued pamphlets and speeches." },
  { name:"Frederick Law Olmsted", dates:"1822–1903", era:"Antebellum", tags:["designer","reformer"], desc:"Landscape architect who designed Central Park and traveled the antebellum South, writing influential accounts of slavery's economic and social effects that shaped Northern opinion." },

  // ── CIVIL WAR ──
  { name:"Abraham Lincoln", dates:"1809–1865", era:"Civil War", tags:["president","leader"], desc:"Sixteenth President who led the nation through its greatest crisis. Issued the Emancipation Proclamation (1863), transforming the Civil War into a war for human freedom. His Gettysburg Address redefined the nation's founding ideals. Assassinated by John Wilkes Booth five days after Lee's surrender." },
  { name:"Jefferson Davis", dates:"1808–1889", era:"Civil War", tags:["Confederate","president"], desc:"President of the Confederate States of America throughout the Civil War; his rigid personality, conflicts with Confederate governors over states' rights, and inability to create a unified Southern nationalism contributed to the Confederacy's defeat." },
  { name:"Ulysses S. Grant", dates:"1822–1885", era:"Civil War", tags:["military","president"], desc:"Union general whose tenacious battlefield strategy — grinding attrition at Vicksburg, the Overland Campaign, and the Siege of Petersburg — brought the Confederacy to its knees. As eighteenth President, he championed Reconstruction and civil rights." },
  { name:"William Tecumseh Sherman", dates:"1820–1891", era:"Civil War", tags:["military"], desc:"Union general who pioneered 'total war' with his March to the Sea (1864), destroying Confederate infrastructure and civilian morale across Georgia, hastening the war's end." },
  { name:"Robert E. Lee", dates:"1807–1870", era:"Civil War", tags:["Confederate","military"], desc:"Commander of the Confederate Army of Northern Virginia whose tactical brilliance at Fredericksburg and Chancellorsville made him formidable, though his aggressive strategy depleted Confederate manpower. Surrendered to Grant at Appomattox Court House, April 9, 1865." },
  { name:"Stonewall Jackson", dates:"1824–1863", era:"Civil War", tags:["Confederate","military"], desc:"Confederate general celebrated for his lightning-fast flanking maneuvers in the Shenandoah Valley Campaign and at Chancellorsville; accidentally shot by his own troops and died, a major blow to Confederate fortunes." },
  { name:"Clara Barton", dates:"1821–1912", era:"Civil War", tags:["women","nurse","reformer"], desc:"Known as the 'Angel of the Battlefield,' she organized medical supplies and nursing care on Civil War battlefields and later founded the American Red Cross." },
  { name:"Thaddeus Stevens", dates:"1792–1868", era:"Civil War", tags:["politician","Radical Republican"], desc:"Radical Republican congressman who drove Reconstruction legislation and the 14th Amendment; believed the South must be treated as a conquered province and transformed from the ground up." },
  { name:"Charles Sumner", dates:"1811–1874", era:"Civil War", tags:["politician","Radical Republican"], desc:"Massachusetts senator whose antislavery 'Crime Against Kansas' speech prompted Representative Preston Brooks to beat him unconscious with a cane on the Senate floor in 1856 — an image that galvanized Northern antislavery sentiment." },
  { name:"Frederick Douglass", dates:"1818–1895", era:"Civil War", tags:["abolitionist","advisor","Black American"], desc:"Advised Lincoln throughout the war, pushed for Black enlistment in the Union Army, and met with Lincoln multiple times — a relationship unique in American presidential history." },
  { name:"Mary Edwards Walker", dates:"1832–1919", era:"Civil War", tags:["women","doctor","military"], desc:"The only woman to receive the Medal of Honor, she served as an army surgeon during the Civil War and was a lifelong women's rights advocate." },
  { name:"Harriet Jacobs", dates:"1813–1897", era:"Civil War", tags:["enslaved","writer","Black American","women"], desc:"Enslaved woman who hid in a crawlspace for seven years before escaping; her 1861 'Incidents in the Life of a Slave Girl' was the first autobiography by an enslaved Black woman." },

  // ── RECONSTRUCTION ──
  { name:"Andrew Johnson", dates:"1808–1875", era:"Reconstruction", tags:["president"], desc:"Seventeenth President whose lenient Reconstruction plan restored Southern states quickly without protecting freedpeople. His vetoes of civil rights legislation led to his impeachment by the House (1868) — the first presidential impeachment — though he survived removal by one Senate vote." },
  { name:"Hiram Revels", dates:"1827–1901", era:"Reconstruction", tags:["politician","Black American"], desc:"First Black U.S. Senator, representing Mississippi in 1870–71; an AME minister who also served as president of Alcorn State University." },
  { name:"Blanche Bruce", dates:"1841–1898", era:"Reconstruction", tags:["politician","Black American"], desc:"First Black American to serve a full term in the U.S. Senate (1875–1881), representing Mississippi." },
  { name:"Pinckney Pinchback", dates:"1837–1921", era:"Reconstruction", tags:["politician","Black American"], desc:"First Black governor in U.S. history, serving briefly as acting governor of Louisiana in 1872–73." },
  { name:"Robert Brown Elliott", dates:"1842–1884", era:"Reconstruction", tags:["politician","Black American"], desc:"South Carolina congressman and one of the most effective Black legislators of the Reconstruction era, renowned for his powerful floor speeches defending civil rights." },
  { name:"Susie King Taylor", dates:"1848–1912", era:"Reconstruction", tags:["nurse","Black American","women"], desc:"Formerly enslaved woman who served as a nurse and teacher for the first Black regiment in the Union Army; wrote the only memoir by a Black woman about the Civil War." },

  // ── GILDED AGE ──
  { name:"John D. Rockefeller", dates:"1839–1937", era:"Gilded Age", tags:["entrepreneur","monopolist"], desc:"Founded Standard Oil in 1870 and used horizontal integration, predatory pricing, and secret railroad rebates to control 90% of U.S. oil refining by 1882. His trust became the defining example of monopoly power and the primary target of antitrust regulation." },
  { name:"Andrew Carnegie", dates:"1835–1919", era:"Gilded Age", tags:["entrepreneur","industrialist"], desc:"Scottish immigrant who dominated the American steel industry through vertical integration and ruthless cost-cutting. After selling Carnegie Steel for $480 million, he gave away nearly his entire fortune, articulating 'The Gospel of Wealth.'" },
  { name:"J.P. Morgan", dates:"1837–1913", era:"Gilded Age", tags:["financier","banker"], desc:"America's most powerful banker who organized railroad financing, bailed out the U.S. Treasury during the Panic of 1893, and created U.S. Steel (the first billion-dollar corporation) in 1901; his power convinced Congress to create the Federal Reserve." },
  { name:"Cornelius Vanderbilt", dates:"1794–1877", era:"Gilded Age", tags:["entrepreneur","railroad"], desc:"Built a steamship and railroad empire, consolidating the New York Central Railroad and accumulating a fortune that made him the wealthiest American of his era." },
  { name:"Thomas Edison", dates:"1847–1931", era:"Gilded Age", tags:["inventor","entrepreneur"], desc:"Prolific inventor with over 1,000 patents, including the phonograph, practical incandescent light bulb, and motion picture camera. His Menlo Park laboratory pioneered organized industrial research and development." },
  { name:"Nikola Tesla", dates:"1856–1943", era:"Gilded Age", tags:["inventor","scientist"], desc:"Serbian-American inventor whose alternating current (AC) system, developed partly in competition with Edison's DC, became the global standard for electrical power transmission." },
  { name:"Mark Twain (Samuel Clemens)", dates:"1835–1910", era:"Gilded Age", tags:["writer","intellectual"], desc:"Novelist and satirist who coined the term 'Gilded Age' and authored 'Adventures of Huckleberry Finn,' America's quintessential novel exploring race, freedom, and identity." },
  { name:"Ida Tarbell", dates:"1857–1944", era:"Gilded Age", tags:["journalist","muckraker","women"], desc:"Investigative journalist whose 19-part series on Standard Oil (1902–04) documented Rockefeller's illegal practices in exhaustive detail, ultimately leading to the Supreme Court-ordered breakup of Standard Oil in 1911." },
  { name:"Jacob Riis", dates:"1849–1914", era:"Gilded Age", tags:["journalist","reformer"], desc:"Danish-American photojournalist whose 'How the Other Half Lives' (1890) exposed tenement conditions in New York City with shocking photographs, galvanizing Progressive Era housing reform." },
  { name:"Jane Addams", dates:"1860–1935", era:"Gilded Age", tags:["reformer","women","settlement house"], desc:"Founded Hull House in Chicago (1889), pioneering the settlement house movement. A leading Progressive Era reformer and pacifist who co-founded the ACLU and won the Nobel Peace Prize in 1931." },
  { name:"Ida B. Wells", dates:"1862–1931", era:"Gilded Age", tags:["journalist","activist","Black American","women"], desc:"Crusading journalist documenting lynching with statistical rigor in 'Southern Horrors' (1892). She co-founded the NAACP, organized Black women's clubs, and fought tirelessly against racial violence despite constant death threats." },
  { name:"Booker T. Washington", dates:"1856–1915", era:"Gilded Age", tags:["educator","leader","Black American"], desc:"Founded Tuskegee Institute and became the most influential Black leader of the late 19th century by advocating 'accommodationism' — Black economic self-improvement through vocational training. His 1895 Atlanta Compromise speech accepted social segregation in exchange for economic opportunity." },
  { name:"W.E.B. Du Bois", dates:"1868–1963", era:"Gilded Age", tags:["intellectual","activist","Black American"], desc:"First Black American to earn a PhD from Harvard, Du Bois challenged Washington's accommodationism, arguing for the 'Talented Tenth' — higher education for Black leaders who would demand full civil rights. Co-founded the NAACP in 1909." },
  { name:"Samuel Gompers", dates:"1850–1924", era:"Gilded Age", tags:["labor","organizer"], desc:"Founded and led the American Federation of Labor (AFL), championing 'bread and butter' unionism focused on wages, hours, and working conditions; dominated the American labor movement for four decades." },
  { name:"Eugene V. Debs", dates:"1855–1926", era:"Gilded Age", tags:["labor","socialist"], desc:"Led the Pullman Strike (1894), was imprisoned, and ran for president five times as a Socialist — once from prison in 1920 — receiving nearly a million votes; symbolized the radical labor movement." },
  { name:"Chief Joseph (Hinmahtooyahlatkekt)", dates:"1840–1904", era:"Gilded Age", tags:["Native American","leader"], desc:"Nez Perce leader who led a tactical military retreat of 1,170 miles through the Rockies (1877) before being forced to surrender just 40 miles from the Canadian border; his surrender speech became one of history's most moving statements." },
  { name:"Sitting Bull (Tatanka-Iyotanka)", dates:"c.1831–1890", era:"Gilded Age", tags:["Native American","leader"], desc:"Hunkpapa Lakota holy man and war chief who led resistance to U.S. expansion, oversaw the defeat of Custer at Little Bighorn (1876), and was later killed during the Ghost Dance movement." },
  { name:"William Jennings Bryan", dates:"1860–1925", era:"Gilded Age", tags:["politician","orator"], desc:"Three-time Democratic presidential candidate whose 'Cross of Gold' speech electrified the 1896 convention, championing silver coinage for debtors against gold-standard creditors; personified agrarian populism." },
  { name:"Helen Hunt Jackson", dates:"1830–1885", era:"Gilded Age", tags:["writer","activist"], desc:"Wrote 'A Century of Dishonor' (1881) documenting federal treaty violations against Native Americans, galvanizing public sympathy for Native peoples." },
  { name:"Grover Cleveland", dates:"1837–1908", era:"Gilded Age", tags:["president"], desc:"Only president to serve two non-consecutive terms (22nd and 24th); known for vetoing excessive pensions and opposing high tariff protection; signed the Dawes Act." },
  { name:"William McKinley", dates:"1843–1901", era:"Gilded Age", tags:["president"], desc:"Twenty-fifth President who led the U.S. into the Spanish-American War (1898), acquiring Guam, Puerto Rico, and the Philippines; assassinated in 1901, succeeded by Theodore Roosevelt." },
  { name:"Henry George", dates:"1839–1897", era:"Gilded Age", tags:["economist","reformer"], desc:"Political economist whose 'Progress and Poverty' (1879) proposed the 'single tax' on land to eliminate poverty; enormously influential in Progressive Era reform debates." },
  { name:"Mary Harris 'Mother' Jones", dates:"1837–1930", era:"Gilded Age", tags:["labor","activist","women"], desc:"Irish-born union organizer who spent decades in mining camps and textile mills mobilizing workers; called 'the most dangerous woman in America' for her confrontational tactics." },
  { name:"George Armstrong Custer", dates:"1839–1876", era:"Gilded Age", tags:["military"], desc:"U.S. Army officer whose catastrophic defeat at Little Bighorn (1876) by combined Sioux and Cheyenne forces became the most famous Native American victory against the U.S. military." },
  { name:"Frederick Winslow Taylor", dates:"1856–1915", era:"Gilded Age", tags:["engineer","management"], desc:"Developed 'scientific management' (Taylorism) — systematic time-and-motion studies to maximize industrial efficiency, transforming factory management and labor relations." },
  { name:"Frances Willard", dates:"1839–1898", era:"Gilded Age", tags:["reformer","women","temperance"], desc:"President of the Women's Christian Temperance Union who expanded the WCTU's agenda from prohibition to encompass labor reform, women's suffrage, and social welfare — making it the largest women's organization of the 19th century." },
  { name:"Terence Powderly", dates:"1849–1924", era:"Gilded Age", tags:["labor","organizer"], desc:"Led the Knights of Labor, the first major industrial union organizing skilled and unskilled workers including women and Black Americans in the 1880s." },
  { name:"Elizabeth Cady Stanton", dates:"1815–1902", era:"Gilded Age", tags:["women's rights","activist"], desc:"Continued her suffrage advocacy through the Gilded Age, writing 'The Woman's Bible' (1895) and arguing for a broader vision of women's liberation beyond the vote." },

  // ── PROGRESSIVE ERA ──
  { name:"Theodore Roosevelt", dates:"1858–1919", era:"Progressive Era", tags:["president","conservationist"], desc:"Twenty-sixth President who busted 44 trusts, championed consumer protection (Pure Food and Drug Act, Meat Inspection Act), established 150 national forests and 5 national parks, and won the Nobel Peace Prize for mediating the Russo-Japanese War. His 'Square Deal' set the template for activist presidents." },
  { name:"Woodrow Wilson", dates:"1856–1924", era:"Progressive Era", tags:["president"], desc:"Twenty-eighth President who signed the Federal Reserve Act, Federal Trade Commission Act, and Clayton Antitrust Act in his 'New Freedom' program. Led the U.S. into WWI, proposed the Fourteen Points and League of Nations. A committed white supremacist who re-segregated the federal government." },
  { name:"William Howard Taft", dates:"1857–1930", era:"Progressive Era", tags:["president","judiciary"], desc:"Twenty-seventh President who actually busted more trusts than Roosevelt; split the Republican Party with Roosevelt in 1912. Later served as Chief Justice — the only person to hold both offices." },
  { name:"Robert La Follette", dates:"1855–1925", era:"Progressive Era", tags:["politician","Progressive"], desc:"Wisconsin governor and senator who pioneered direct democracy reforms — primary elections, initiative, referendum, recall — making Wisconsin a 'laboratory of democracy' for Progressive legislation." },
  { name:"Upton Sinclair", dates:"1878–1968", era:"Progressive Era", tags:["writer","muckraker"], desc:"Socialist author whose 'The Jungle' (1906) exposed horrific unsanitary conditions in Chicago meatpacking plants. Though Sinclair intended to highlight worker exploitation, public outrage over contaminated food led directly to the Pure Food and Drug Act." },
  { name:"John Muir", dates:"1838–1914", era:"Progressive Era", tags:["conservationist","writer"], desc:"Scottish-American naturalist who founded the Sierra Club and persuaded Theodore Roosevelt to protect millions of acres of wilderness; called the 'Father of the National Parks.'" },
  { name:"Emma Goldman", dates:"1869–1940", era:"Progressive Era", tags:["anarchist","activist","women"], desc:"Russian-born anarchist who advocated free love, birth control, labor rights, and anti-militarism; deported to Russia in 1919 during the First Red Scare." },
  { name:"Margaret Sanger", dates:"1879–1966", era:"Progressive Era", tags:["activist","women","birth control"], desc:"Nurse who opened America's first birth control clinic (1916) and founded what became Planned Parenthood, fighting for women's reproductive autonomy; her association with eugenicist ideology complicates her legacy." },
  { name:"Louis Brandeis", dates:"1856–1941", era:"Progressive Era", tags:["judiciary","reformer"], desc:"Progressive lawyer and first Jewish Supreme Court Justice, known for 'the Brandeis Brief' pioneering the use of social science evidence in law; championed workers' rights and opposed corporate concentration." },
  { name:"W.E.B. Du Bois", dates:"1868–1963", era:"Progressive Era", tags:["intellectual","activist","Black American"], desc:"Co-founded the NAACP in 1909 and edited The Crisis magazine, making the Progressive Era case for immediate civil rights rather than accommodation." },
  { name:"Lincoln Steffens", dates:"1866–1936", era:"Progressive Era", tags:["journalist","muckraker"], desc:"Muckraking journalist whose 'The Shame of the Cities' series exposed political machine corruption in American cities, galvanizing Progressive Era municipal reform." },
  { name:"Florence Kelley", dates:"1859–1932", era:"Progressive Era", tags:["reformer","women","labor"], desc:"Resident of Hull House who successfully lobbied for Illinois factory inspection laws and an 8-hour workday for women; became chief factory inspector and later led the National Consumers League." },
  { name:"Carrie Chapman Catt", dates:"1859–1947", era:"Progressive Era", tags:["women's rights","suffrage"], desc:"Strategist who led NAWSA through its final push for the 19th Amendment, developing the 'Winning Plan' that targeted key states and secured ratification in 1920 after 72 years of struggle." },
  { name:"Triangle Shirtwaist victims (146 workers)", dates:"1911", era:"Progressive Era", tags:["labor","women"], desc:"146 garment workers — mostly young immigrant women — who died in the Triangle Shirtwaist Factory fire when locked exits prevented escape; their deaths became a catalyst for landmark fire safety and labor legislation in New York and nationally." },

  // ── WWI ──
  { name:"John J. Pershing", dates:"1860–1948", era:"WWI", tags:["military"], desc:"Commander of the American Expeditionary Forces in World War I; previously led the punitive expedition against Pancho Villa in Mexico." },
  { name:"Henry Cabot Lodge", dates:"1850–1924", era:"WWI", tags:["politician"], desc:"Republican Senate Majority Leader whose opposition to the League of Nations treaty defeated U.S. entry, a pivotal moment in American foreign policy history." },
  { name:"A. Mitchell Palmer", dates:"1872–1936", era:"WWI", tags:["politician"], desc:"Attorney General who ordered the Palmer Raids (1919–20), mass arrests of suspected radicals and immigrants during the First Red Scare." },
  { name:"W.E.B. Du Bois", dates:"1868–1963", era:"WWI", tags:["intellectual","Black American"], desc:"Controversially urged Black Americans to support WWI with 'Close Ranks,' hoping wartime service would earn recognition and rights — a position he later regretted as the promised equality failed to materialize." },
  { name:"Charles Schenck", dates:"1884–?", era:"WWI", tags:["activist"], desc:"Socialist who distributed leaflets opposing the draft during WWI; the Supreme Court's Schenck v. United States ruling established the 'clear and present danger' test for free speech limitations." },

  // ── 1920s ──
  { name:"Warren G. Harding", dates:"1865–1923", era:"1920s", tags:["president"], desc:"Twenty-ninth President whose administration was engulfed in scandal — most notably the Teapot Dome oil bribery scandal — though Harding himself died before the worst was revealed." },
  { name:"Calvin Coolidge", dates:"1872–1933", era:"1920s", tags:["president"], desc:"Thirtieth President whose 'Silent Cal' persona embodied laissez-faire economic policy; his hands-off approach to business contributed to the speculation bubble that preceded the Great Depression." },
  { name:"Herbert Hoover", dates:"1874–1964", era:"1920s", tags:["president"], desc:"Thirty-first President who presided over the onset of the Great Depression; his faith in 'rugged individualism' and opposition to direct federal relief made him deeply unpopular as unemployment soared to 25%." },
  { name:"Marcus Garvey", dates:"1887–1940", era:"1920s", tags:["activist","Black American","Pan-Africanism"], desc:"Jamaican-born Black nationalist who founded the UNIA and the Black Star Line shipping company, championing Pan-Africanism; his mass movement was the largest Black organization in U.S. history until the 1960s." },
  { name:"Langston Hughes", dates:"1902–1967", era:"1920s", tags:["poet","Black American","Harlem Renaissance"], desc:"Poet, playwright, and novelist who became the leading voice of the Harlem Renaissance, capturing Black life, jazz rhythms, and the Great Migration in works like 'The Weary Blues.'" },
  { name:"Zora Neale Hurston", dates:"1891–1960", era:"1920s", tags:["writer","Black American","women","Harlem Renaissance"], desc:"Harlem Renaissance novelist and anthropologist who celebrated Southern Black folk culture in 'Their Eyes Were Watching God' (1937); rediscovered by Alice Walker in the 1970s after dying in obscurity." },
  { name:"Duke Ellington", dates:"1899–1974", era:"1920s", tags:["musician","Black American"], desc:"Jazz composer, pianist, and bandleader who defined American big band jazz at Harlem's Cotton Club and composed over 1,000 works, elevating jazz to an art form." },
  { name:"Louis Armstrong", dates:"1901–1971", era:"1920s", tags:["musician","Black American"], desc:"New Orleans-born trumpet virtuoso whose improvisational genius defined jazz and made it a global art form; his recordings with the Hot Five and Hot Seven in the 1920s are foundational texts of American music." },
  { name:"Charles Lindbergh", dates:"1902–1974", era:"1920s", tags:["aviator"], desc:"Made the first solo nonstop transatlantic flight (1927) in the Spirit of St. Louis, becoming America's greatest celebrity; his isolationist America First activism before WWII tarnished his legacy." },
  { name:"F. Scott Fitzgerald", dates:"1896–1940", era:"1920s", tags:["writer"], desc:"Novelist who defined the Jazz Age with 'The Great Gatsby' (1925), exploring the American Dream's corruption beneath the glittering surface of 1920s prosperity and inequality." },
  { name:"Henry Ford", dates:"1863–1947", era:"1920s", tags:["entrepreneur","industrialist"], desc:"Pioneer of the assembly line who made the automobile affordable for ordinary Americans with the Model T; introduced the $5 work day and 40-hour week. Also a virulent antisemite whose writings influenced Adolf Hitler." },
  { name:"Clarence Darrow", dates:"1857–1938", era:"1920s", tags:["lawyer"], desc:"Legendary defense attorney who famously sparred with William Jennings Bryan in the Scopes Trial (1925), defending science education against fundamentalist challenges." },
  { name:"Aimee Semple McPherson", dates:"1890–1944", era:"1920s", tags:["religious","women"], desc:"Founder of the International Church of the Foursquare Gospel who pioneered religious broadcasting, turning evangelical Christianity into a mass media phenomenon and prefiguring televangelism." },

  // ── NEW DEAL ──
  { name:"Franklin D. Roosevelt", dates:"1882–1945", era:"New Deal", tags:["president","leader"], desc:"Thirty-second President whose New Deal programs — Social Security, the FDIC, the SEC, the TVA, the NLRA — fundamentally restructured the relationship between the federal government and citizens, establishing the modern welfare state. Led the U.S. through most of World War II." },
  { name:"Eleanor Roosevelt", dates:"1884–1962", era:"New Deal", tags:["First Lady","activist","women"], desc:"Transformed the role of First Lady from ceremonial to activist. Championed civil rights, lobbied for anti-lynching legislation, ensured New Deal programs reached women and Black Americans. As U.S. Representative to the UN, helped draft the Universal Declaration of Human Rights (1948)." },
  { name:"Frances Perkins", dates:"1880–1965", era:"New Deal", tags:["women","labor","government"], desc:"First woman Cabinet member, serving as FDR's Secretary of Labor for all 12 years; the primary architect of the Social Security Act, the Fair Labor Standards Act (minimum wage, 40-hour week), and the National Labor Relations Act." },
  { name:"Huey Long", dates:"1893–1935", era:"New Deal", tags:["politician","populist"], desc:"Populist Louisiana governor and senator whose 'Share Our Wealth' program proposed massive redistribution of income from the wealthy; seen as a potential threat to FDR, he was assassinated in 1935." },
  { name:"John Steinbeck", dates:"1902–1968", era:"New Deal", tags:["writer"], desc:"Novelist whose 'The Grapes of Wrath' (1939) humanized the plight of Dust Bowl migrants, winning the Pulitzer Prize and intensifying pressure for farm labor reforms." },
  { name:"Mary McLeod Bethune", dates:"1875–1955", era:"New Deal", tags:["educator","activist","Black American","women"], desc:"Educator who founded Bethune-Cookman College and served as Director of Negro Affairs in FDR's New Deal — the highest federal position held by a Black woman to that point." },
  { name:"A. Philip Randolph", dates:"1889–1979", era:"New Deal", tags:["labor","activist","Black American"], desc:"Organized the Brotherhood of Sleeping Car Porters, the first major Black union. Threatened a March on Washington in 1941, forcing FDR to desegregate defense industries via Executive Order 8802." },
  { name:"Dorothea Lange", dates:"1895–1965", era:"New Deal", tags:["photographer","women"], desc:"Documentary photographer whose Dust Bowl and Depression-era images — especially 'Migrant Mother' — defined the visual memory of the Great Depression and shaped public support for New Deal relief programs." },
  { name:"Harold Ickes", dates:"1874–1952", era:"New Deal", tags:["government","conservationist"], desc:"FDR's Secretary of the Interior who administered the Public Works Administration, oversaw Native American policy reforms under the Indian Reorganization Act, and notably allowed Marian Anderson to perform at the Lincoln Memorial." },

  // ── WWII ──
  { name:"Harry S. Truman", dates:"1884–1972", era:"WWII", tags:["president"], desc:"Thirty-third President who made the decision to drop atomic bombs on Hiroshima and Nagasaki. Desegregated the military by executive order, launched the Marshall Plan and the Truman Doctrine to contain Soviet expansion, and led NATO's response to the Korean War." },
  { name:"Dwight D. Eisenhower", dates:"1890–1969", era:"WWII", tags:["military","president"], desc:"Supreme Allied Commander who planned and executed the D-Day invasion (June 6, 1944), the largest seaborne invasion in history. As thirty-fourth President, he expanded the interstate highway system and warned against the growing 'military-industrial complex.'" },
  { name:"Douglas MacArthur", dates:"1880–1964", era:"WWII", tags:["military"], desc:"Commander in the Pacific Theater who island-hopped toward Japan, oversaw Japan's postwar occupation, and led UN forces in Korea until fired by Truman for insubordination in 1951." },
  { name:"J. Robert Oppenheimer", dates:"1904–1967", era:"WWII", tags:["scientist"], desc:"Scientific director of the Manhattan Project who led the team that developed the first atomic bombs; later stripped of his security clearance during McCarthyism, becoming a martyr for academic freedom." },
  { name:"Fred Korematsu", dates:"1919–2005", era:"WWII", tags:["activist","Japanese American"], desc:"Japanese American who refused to comply with the forced relocation order during WWII and brought Korematsu v. United States to the Supreme Court; his conviction was later vacated, and he became a civil rights icon." },
  { name:"Dorie Miller", dates:"1919–1943", era:"WWII", tags:["military","Black American"], desc:"Black Navy cook who manned an anti-aircraft gun during the Pearl Harbor attack, shooting down Japanese planes despite having no gunnery training; awarded the Navy Cross." },
  { name:"Oveta Culp Hobby", dates:"1905–1995", era:"WWII", tags:["military","women"], desc:"First director of the Women's Army Corps (WACs) during WWII; later became the second woman to serve in a presidential cabinet as Secretary of Health, Education, and Welfare under Eisenhower." },
  { name:"George Marshall", dates:"1880–1959", era:"WWII", tags:["military","diplomat"], desc:"Army Chief of Staff who organized the WWII military effort, then as Secretary of State proposed the Marshall Plan — $13 billion in European reconstruction aid that prevented communist takeover of Western Europe and won him the Nobel Peace Prize." },
  { name:"Henry Kaiser", dates:"1882–1967", era:"WWII", tags:["entrepreneur","industry"], desc:"Industrialist who pioneered mass-production shipbuilding, reducing the time to build a Liberty Ship from a year to four days, enabling the Allied supply chain." },

  // ── COLD WAR ──
  { name:"George Kennan", dates:"1904–2005", era:"Cold War", tags:["diplomat","intellectual"], desc:"Diplomat and historian who wrote the 'Long Telegram' and the 'X Article' articulating the strategy of 'containment' — the foundational doctrine of U.S. Cold War foreign policy." },
  { name:"Joseph McCarthy", dates:"1908–1957", era:"Cold War", tags:["politician","anti-communist"], desc:"Wisconsin senator whose reckless accusations created a climate of fear and political repression ('McCarthyism') from 1950–54; his downfall came when attorney Joseph Welch asked him on live TV: 'Have you no sense of decency?'" },
  { name:"Rosa Parks", dates:"1913–2005", era:"Cold War", tags:["activist","Black American","women","civil rights"], desc:"NAACP secretary whose refusal to give up her bus seat in Montgomery, Alabama (December 1, 1955) ignited the 381-day Montgomery Bus Boycott, launching the modern civil rights movement." },
  { name:"Martin Luther King Jr.", dates:"1929–1968", era:"Cold War", tags:["civil rights","leader","Black American"], desc:"Baptist minister who led the civil rights movement from the Montgomery Bus Boycott through his assassination. Organized the SCLC, led the Birmingham campaign (1963), delivered the 'I Have a Dream' speech, won the Nobel Peace Prize (1964), and championed the Civil Rights Act and Voting Rights Act. Assassinated April 4, 1968." },
  { name:"Thurgood Marshall", dates:"1908–1993", era:"Cold War", tags:["lawyer","civil rights","Black American"], desc:"NAACP attorney who argued and won Brown v. Board of Education (1954), overturning 'separate but equal.' Later appointed as the first Black Supreme Court Justice (1967)." },
  { name:"John Lewis", dates:"1940–2020", era:"Cold War", tags:["civil rights","politician","Black American"], desc:"SNCC chairman who was beaten bloody on Bloody Sunday at Selma's Edmund Pettus Bridge (1965) demanding voting rights; later served for over 30 years in Congress, becoming the moral conscience of the House." },
  { name:"Fannie Lou Hamer", dates:"1917–1977", era:"Cold War", tags:["civil rights","Black American","women"], desc:"Mississippi sharecropper who became a towering voting rights activist; her televised testimony before the 1964 Democratic National Convention about beatings she endured electrified the nation." },
  { name:"Malcolm X (El-Hajj Malik El-Shabazz)", dates:"1925–1965", era:"Cold War", tags:["civil rights","Black American","Black nationalism"], desc:"Nation of Islam minister and Black nationalist who challenged King's nonviolent integrationism, preaching Black pride and self-defense. After a pilgrimage to Mecca transformed his views, he was assassinated in 1965." },
  { name:"John F. Kennedy", dates:"1917–1963", era:"Cold War", tags:["president"], desc:"Thirty-fifth President who navigated the Cuban Missile Crisis (1962) through tense back-channel negotiation, avoiding nuclear war. Established the Peace Corps, advanced civil rights, and set the moon mission goal. Assassinated in Dallas, November 22, 1963." },
  { name:"Lyndon B. Johnson", dates:"1908–1973", era:"Cold War", tags:["president"], desc:"Thirty-sixth President whose 'Great Society' produced more landmark domestic legislation than any president since FDR: Civil Rights Act (1964), Voting Rights Act (1965), Medicare, Medicaid. However, his escalation of the Vietnam War destroyed his presidency." },
  { name:"Earl Warren", dates:"1891–1974", era:"Cold War", tags:["judiciary"], desc:"Chief Justice whose Warren Court issued landmark rulings: Brown v. Board (desegregation), Engel v. Vitale (school prayer), Miranda v. Arizona (suspects' rights); transformed constitutional law more than any court since Marshall." },
  { name:"Rachel Carson", dates:"1907–1964", era:"Cold War", tags:["scientist","environmentalist","women"], desc:"Marine biologist whose 'Silent Spring' (1962) documented the devastating ecological effects of pesticides on birds and ecosystems, igniting the modern environmental movement and leading to the creation of the EPA." },
  { name:"Betty Friedan", dates:"1921–2006", era:"Cold War", tags:["feminist","women"], desc:"Author of 'The Feminine Mystique' (1963), which identified the 'problem that has no name' — suburban women's unfulfillment — catalyzing second-wave feminism. Co-founded the National Organization for Women (NOW) in 1966." },
  { name:"Barry Goldwater", dates:"1909–1998", era:"Cold War", tags:["politician","conservative"], desc:"Arizona senator whose 1964 presidential campaign launched modern conservatism by popularizing small government, anti-communism, and opposition to the Civil Rights Act as constitutional overreach." },
  { name:"Richard Nixon", dates:"1913–1994", era:"Cold War", tags:["president","politician"], desc:"37th President who opened diplomatic relations with China (1972) and signed détente agreements with the Soviet Union. His administration's involvement in the Watergate break-in and cover-up forced his resignation in 1974, the only president ever to resign." },
  { name:"César Chávez", dates:"1927–1993", era:"Cold War", tags:["labor","activist","Latino"], desc:"Mexican American labor organizer who co-founded the United Farm Workers (UFW) and led nonviolent strikes and nationwide grape and lettuce boycotts to win the first collective bargaining agreements for agricultural workers." },
  { name:"Gloria Steinem", dates:"1934–", era:"Cold War", tags:["feminist","journalist","women"], desc:"Journalist and activist who co-founded Ms. magazine and became the most visible face of second-wave feminism, championing the Equal Rights Amendment and reproductive rights." },
  { name:"George Wallace", dates:"1919–1998", era:"Cold War", tags:["politician","segregationist"], desc:"Alabama governor who declared 'segregation now, segregation tomorrow, segregation forever' and physically blocked Black students from the University of Alabama; his third-party presidential campaigns reshaped the Democratic coalition." },
  { name:"Medgar Evers", dates:"1925–1963", era:"Cold War", tags:["civil rights","Black American"], desc:"NAACP field secretary in Mississippi who organized voter registration drives and was assassinated in his driveway in 1963; his killer was not convicted for 31 years." },
  { name:"Stokely Carmichael (Kwame Ture)", dates:"1941–1998", era:"Cold War", tags:["civil rights","Black Power","Black American"], desc:"SNCC chairman who popularized the term 'Black Power' in 1966, shifting the civil rights movement toward Black nationalism; later joined the Black Panther Party." },

  // ── VIETNAM ──
  { name:"Robert McNamara", dates:"1916–2009", era:"Vietnam", tags:["government","military"], desc:"Secretary of Defense who engineered the massive U.S. escalation in Vietnam using systems analysis and body counts as metrics, later acknowledging in his memoir 'In Retrospect' that he knew early on the war was unwinnable." },
  { name:"Daniel Ellsberg", dates:"1931–2023", era:"Vietnam", tags:["whistleblower","activist"], desc:"Former Defense Department analyst who leaked the Pentagon Papers in 1971 — classified documents showing the government had systematically deceived the public about Vietnam — a watershed moment for press freedom." },
  { name:"Walter Cronkite", dates:"1916–2009", era:"Vietnam", tags:["journalist"], desc:"CBS News anchor whose February 1968 editorial calling Vietnam a 'stalemate' caused LBJ to reportedly say 'If I've lost Cronkite, I've lost Middle America.'" },
  { name:"Tom Hayden", dates:"1939–2016", era:"Vietnam", tags:["activist"], desc:"Wrote the Port Huron Statement (1962), founding document of Students for a Democratic Society (SDS) and the New Left; later a Chicago Eight defendant." },
  { name:"Bob Dylan", dates:"1941–", era:"Vietnam", tags:["musician","activist"], desc:"Singer-songwriter whose early folk protest songs defined the civil rights and antiwar movements' musical voice; awarded the Nobel Prize in Literature (2016)." },

  // ── MODERN ──
  { name:"Ronald Reagan", dates:"1911–2004", era:"Modern", tags:["president","conservative"], desc:"Fortieth President who transformed American politics with massive tax cuts, deregulation, military buildup, and anti-Soviet rhetoric he credited with winning the Cold War. His 'Reagan Revolution' shifted the political center rightward; the Iran-Contra scandal was the gravest crisis of his second term." },
  { name:"Jimmy Carter", dates:"1924–2024", era:"Modern", tags:["president"], desc:"Thirty-ninth President who brokered the Camp David Accords between Israel and Egypt (1978); his presidency was defined by the Iran hostage crisis and stagflation. Later won the Nobel Peace Prize for post-presidential humanitarian work." },
  { name:"George H.W. Bush", dates:"1924–2018", era:"Modern", tags:["president"], desc:"Forty-first President who built the international coalition that expelled Saddam Hussein from Kuwait in the Gulf War (1991) with minimal casualties; lost re-election to Clinton amid economic recession." },
  { name:"Bill Clinton", dates:"1946–", era:"Modern", tags:["president"], desc:"Forty-second President who presided over the longest peacetime economic expansion in U.S. history, signed NAFTA and welfare reform, but was impeached by the House for perjury related to the Monica Lewinsky affair." },
  { name:"George W. Bush", dates:"1946–", era:"Modern", tags:["president"], desc:"Forty-third President who responded to September 11, 2001 by launching the War in Afghanistan and, controversially, the Iraq War based on intelligence about weapons of mass destruction that proved false." },
  { name:"Barack Obama", dates:"1961–", era:"Modern", tags:["president","Black American"], desc:"Forty-fourth President and first Black American to hold the office; passed the Affordable Care Act (2010), ended 'Don't Ask Don't Tell,' oversaw the killing of Osama bin Laden (2011), and negotiated the Iran nuclear deal and Paris Climate Agreement." },
  { name:"Sandra Day O'Connor", dates:"1930–2023", era:"Modern", tags:["judiciary","women"], desc:"First woman appointed to the Supreme Court (by Reagan, 1981); served as a pivotal swing vote for 24 years on cases involving abortion, affirmative action, and voting rights." },
  { name:"Ruth Bader Ginsburg", dates:"1933–2020", era:"Modern", tags:["judiciary","women"], desc:"Second woman on the Supreme Court, appointed by Clinton in 1993; as a lawyer had argued landmark sex discrimination cases before the Court in the 1970s; became a liberal icon nicknamed 'the Notorious RBG.'" },
  { name:"Harvey Milk", dates:"1930–1978", era:"Modern", tags:["LGBTQ+","activist","politician"], desc:"First openly gay elected official in California history, serving on San Francisco's Board of Supervisors; assassinated in 1978, his martyrdom accelerated the LGBTQ+ rights movement." },
  { name:"Phyllis Schlafly", dates:"1924–2016", era:"Modern", tags:["conservative","activist","women"], desc:"Conservative activist whose STOP ERA campaign successfully blocked ratification of the Equal Rights Amendment in the 1970s; organized the Religious Right's entry into Republican politics." },
  { name:"Colin Powell", dates:"1937–2021", era:"Modern", tags:["military","government","Black American"], desc:"First Black National Security Advisor, Chairman of the Joint Chiefs during the Gulf War, and first Black Secretary of State; his UN testimony on Iraqi WMDs helped build the case for the Iraq War, which he later called a 'blot' on his record." },
  { name:"Anita Hill", dates:"1956–", era:"Modern", tags:["activist","women"], desc:"Law professor whose 1991 Senate testimony alleging sexual harassment by Clarence Thomas during his Supreme Court confirmation hearings galvanized the women's rights movement and the 'Year of the Woman' election in 1992." },
  { name:"Steve Jobs", dates:"1955–2011", era:"Modern", tags:["entrepreneur","inventor"], desc:"Co-founded Apple Computer, revolutionized personal computing with the Macintosh, transformed music distribution with the iPod and iTunes, and launched the smartphone era with the iPhone." },
];



/* PASTE YOUR EXISTING FULL EVENTS ARRAY HERE, UNCHANGED */
const eventsData = [
 // ── COLONIAL ──
  { name:"Jamestown Founded", year:"1607", era:"Colonial", types:["political"], significance:"First permanent English settlement in North America; established precedent for English colonization and the plantation system.", desc:"English settlers established Jamestown, Virginia, the first permanent English settlement in North America. The colony struggled with starvation, disease, and conflict with the Powhatan Confederacy but survived, establishing tobacco as a cash crop that made Virginia economically viable and introduced African enslaved laborers in 1619." },
  { name:"Mayflower Compact", year:"1620", era:"Colonial", types:["political","law"], significance:"First self-governing document in the colonies; early precedent for consent of the governed.", desc:"Forty-one Pilgrim men aboard the Mayflower signed a brief covenant creating a 'civil body politic' and pledging to make 'just and equal laws' for the general good. Though modest in scope, it established the principle that government derives its authority from the consent of the governed — a cornerstone of American democratic theory." },
  { name:"Bacon's Rebellion", year:"1676", era:"Colonial", types:["political","social"], significance:"Alarmed planters into replacing indentured servants with enslaved Africans, accelerating the growth of race-based slavery.", desc:"Nathaniel Bacon led an armed uprising of frontier settlers, poor whites, and formerly enslaved people against Virginia's Governor Berkeley, burning Jamestown to the ground. Although quickly suppressed after Bacon's death from dysentery, the rebellion's multiracial coalition frightened the planter class, who responded by shifting from indentured servitude to permanent, race-based African slavery." },
  { name:"Salem Witch Trials", year:"1692", era:"Colonial", types:["social","religious"], significance:"Demonstrated dangers of mass hysteria and religious extremism; later influenced Enlightenment critiques of superstition.", desc:"Hysteria in Salem Village, Massachusetts led to accusations of witchcraft against 200 people; 19 were executed by hanging and one pressed to death. Beginning with accusations by young girls in the household of minister Samuel Parris, the crisis reflected social tensions, theological anxieties, and legal failures of due process. Governor Phips eventually dissolved the court." },
  { name:"Zenger Trial", year:"1735", era:"Colonial", types:["law"], significance:"Early precedent for freedom of the press and truth as a defense in libel cases.", desc:"Printer John Peter Zenger was acquitted of seditious libel after publishing criticism of New York's royal governor. His lawyer Andrew Hamilton argued that truth should be a defense against libel charges — a novel legal argument. The verdict established an early American tradition of press freedom, though it had no immediate legal precedent." },
  { name:"French & Indian War", year:"1754–1763", era:"Colonial", types:["war","foreign"], significance:"Massive British debt led to taxation of colonies, igniting the road to revolution; Proclamation of 1763 fueled westward tensions.", desc:"The North American theater of the global Seven Years' War pitted Britain and its colonial allies against France and various Native American nations. British victory removed France from the continent but left Britain deeply in debt, prompting Parliament to tax the colonies to pay for their defense — a decision that set in motion the events leading to revolution." },
  { name:"Proclamation of 1763", year:"1763", era:"Colonial", types:["political","law"], significance:"Angered colonial speculators and settlers who saw it as a violation of their rights to westward expansion.", desc:"Following the French & Indian War and Pontiac's Rebellion, King George III issued a proclamation forbidding colonial settlement west of the Appalachian Mountains. Intended to reduce costly frontier conflicts and appease Native allies, it infuriated land speculators like George Washington and thousands of settlers who had expected to claim western lands." },

  // ── REVOLUTION ──
  { name:"Stamp Act", year:"1765", era:"Revolution", types:["law","political"], significance:"First direct tax on colonies; sparked 'no taxation without representation' resistance and colonial unity.", desc:"Parliament imposed direct taxes on colonial printed materials — newspapers, legal documents, pamphlets, and even playing cards — requiring a royal stamp. Colonists protested with boycotts, the Stamp Act Congress (the first inter-colonial legislative body), and violent intimidation of stamp distributors. The act was repealed in 1766, but Parliament simultaneously passed the Declaratory Act asserting its right to tax colonies." },
  { name:"Boston Massacre", year:"1770", era:"Revolution", types:["political","social"], significance:"Became a powerful propaganda tool for patriots, demonstrating British tyranny to colonial audiences.", desc:"On March 5, 1770, a crowd of colonists harassed British soldiers outside the Custom House on King Street. Soldiers fired into the crowd, killing five people including Crispus Attucks. Paul Revere's famous engraving — depicting it as a deliberate slaughter — became one of the most effective pieces of political propaganda in American history, inflaming colonial opinion against British rule." },
  { name:"Boston Tea Party", year:"1773", era:"Revolution", types:["political"], significance:"Led directly to the Intolerable Acts, which pushed colonies to convene the First Continental Congress.", desc:"In response to the Tea Act granting the British East India Company a monopoly on colonial tea sales, members of the Sons of Liberty disguised as Mohawk Indians boarded three ships in Boston Harbor and dumped 342 chests of tea into the water. Parliament's furious response — the Intolerable Acts — closing the port of Boston and revoking Massachusetts's charter — united the colonies against British coercion." },
  { name:"Declaration of Independence", year:"1776", era:"Revolution", types:["political","law"], significance:"Defined American democratic ideals; 'all men are created equal' became the foundation for future civil rights arguments.", desc:"Drafted primarily by Thomas Jefferson and adopted by the Continental Congress on July 4, 1776, the Declaration formally severed ties with Britain while articulating Enlightenment principles of natural rights, consent of the governed, and the right to revolution. Its statement that 'all men are created equal' endowed with 'inalienable rights' to 'life, liberty, and the pursuit of happiness' became the nation's most contested and aspirational founding ideal." },
  { name:"Battle of Saratoga", year:"1777", era:"Revolution", types:["war"], significance:"Turning point of the Revolutionary War; convinced France to enter as an American ally.", desc:"Two engagements in upstate New York resulted in British General Burgoyne's surrender of 5,700 men to American forces under General Gates — the first major American victory. The dramatic win convinced France that the Continental Army could defeat the British, leading France to formally ally with the United States in February 1778, providing the money, troops, and naval power that made ultimate American victory possible." },
  { name:"Battle of Yorktown", year:"1781", era:"Revolution", types:["war"], significance:"Effectively ended the Revolutionary War and secured American independence.", desc:"American and French forces under Washington and Rochambeau besieged Cornwallis's British army at Yorktown, Virginia, while the French fleet defeated the British navy at the Battle of the Chesapeake. Trapped, Cornwallis surrendered his army of 8,000 on October 19, 1781. While fighting continued elsewhere, the defeat convinced the British government to negotiate peace." },
  { name:"U.S. Constitution Ratified", year:"1788", era:"Revolution", types:["political","law"], significance:"Created the framework of American government; established separation of powers and federalism.", desc:"After months of state ratification debates between Federalists (Hamilton, Madison, Jay writing The Federalist Papers) and Anti-Federalists (Patrick Henry, George Mason), the Constitution was ratified when New Hampshire became the ninth state to approve it. The compromise that secured ratification — a promise to add a Bill of Rights — led to the first ten amendments in 1791." },

  // ── EARLY REPUBLIC ──
  { name:"Whiskey Rebellion", year:"1794", era:"Early Republic", types:["political"], significance:"First test of federal government's authority to enforce laws; established that the Constitution was enforceable.", desc:"Western Pennsylvania farmers who distilled whiskey rose up against an excise tax imposed by Alexander Hamilton's financial program, killing tax collectors and threatening to march on Pittsburgh. Washington personally led 13,000 militia across the Appalachians in the first and only time a sitting president led troops in the field. The rebellion collapsed without a major battle, establishing federal authority to enforce law." },
  { name:"Alien & Sedition Acts", year:"1798", era:"Early Republic", types:["law","political"], significance:"Led to Virginia and Kentucky Resolutions asserting states' rights; key issue in Jefferson's 1800 election.", desc:"Four laws passed by the Federalist Congress made it harder to become a citizen, allowed deportation of aliens, and criminalized criticism of the federal government. Jefferson and Madison's Virginia and Kentucky Resolutions argued the acts were unconstitutional and states could 'nullify' them — an argument later used by Southern secessionists." },
  { name:"Louisiana Purchase", year:"1803", era:"Early Republic", types:["political","foreign"], significance:"Doubled the size of the United States; raised questions about federal power and the future of slavery.", desc:"Jefferson purchased approximately 828,000 square miles of North America from Napoleon's France for $15 million — less than 3 cents per acre. Despite his own strict constructionist principles (he found no explicit constitutional authority for the purchase), Jefferson rationalized the acquisition. The purchase opened the continent to westward expansion and raised the profound question of whether slavery would extend into new territories." },
  { name:"Marbury v. Madison", year:"1803", era:"Early Republic", types:["law"], significance:"Established judicial review — the Supreme Court's power to strike down unconstitutional acts of Congress.", desc:"Chief Justice John Marshall's unanimous ruling in this case established the doctrine of judicial review — that the Supreme Court has the power to strike down acts of Congress that violate the Constitution. Though it ruled against Jefferson administration holdover William Marbury, the decision vastly expanded the Court's power and established the judiciary as a truly co-equal branch of government." },
  { name:"War of 1812", year:"1812–1815", era:"Early Republic", types:["war","foreign"], significance:"Produced nationalism and 'Era of Good Feelings'; settled U.S.-British border; spurred domestic manufacturing.", desc:"The U.S. declared war on Britain over impressment of American sailors, interference with trade, and British support for Native resistance on the frontier. The war brought British troops to burn Washington D.C., American victories on the Great Lakes, and Andrew Jackson's dramatic win at New Orleans. The Treaty of Ghent essentially restored the prewar status quo, but the war produced a surge of American nationalism." },
  { name:"Monroe Doctrine", year:"1823", era:"Early Republic", types:["foreign","political"], significance:"Asserted U.S. dominance over the Western Hemisphere; later used to justify intervention throughout Latin America.", desc:"In his annual message to Congress, President Monroe declared that the Western Hemisphere was closed to further European colonization and that European intervention in the Americas would be considered a threat to U.S. security. Though the U.S. lacked military power to enforce it at the time, the doctrine became a cornerstone of American foreign policy, invoked repeatedly to justify U.S. involvement in Latin American affairs." },
  { name:"Missouri Compromise", year:"1820", era:"Early Republic", types:["law","political"], significance:"Temporarily resolved slavery's expansion; the 36°30' line became a flashpoint of antebellum politics.", desc:"As Missouri applied for statehood as a slave state, threatening to upset the balance of 11 free and 11 slave states, Henry Clay brokered a deal: Missouri entered as a slave state, Maine as a free state, and slavery was prohibited in the Louisiana Purchase territory north of 36°30' latitude. Jefferson called it 'a fire bell in the night' — an ominous warning of sectional conflict to come." },
  { name:"Indian Removal Act", year:"1830", era:"Early Republic", types:["law","political","social"], significance:"Resulted in the Trail of Tears; established forced removal as federal Indian policy for decades.", desc:"Congress passed legislation authorizing the president to negotiate removal treaties with Native American tribes east of the Mississippi, exchanging their lands for territory to the west. Jackson aggressively implemented the law; when the Supreme Court ruled against removal in Worcester v. Georgia (1832), Jackson reportedly declared 'John Marshall has made his decision, now let him enforce it.' The resulting Trail of Tears killed thousands." },
  { name:"Trail of Tears", year:"1838–1839", era:"Early Republic", types:["political","social"], significance:"Devastating example of federal treatment of Native peoples; killed 4,000+ Cherokee on forced march.", desc:"U.S. soldiers rounded up approximately 16,000 Cherokee from their homelands in Georgia, Tennessee, and the Carolinas and forced them on a march to 'Indian Territory' in present-day Oklahoma. At least 4,000 Cherokee died from exposure, disease, and starvation during the journey. The forced removal of the Five Civilized Tribes became a defining act of Jacksonian Indian policy and American expansion." },

  // ── ANTEBELLUM ──
  { name:"Seneca Falls Convention", year:"1848", era:"Antebellum", types:["social","political"], significance:"Launched the organized women's rights movement; the Declaration of Sentiments became the movement's founding document.", desc:"Organized by Elizabeth Cady Stanton and Lucretia Mott, the first women's rights convention in U.S. history met at Seneca Falls, New York. The 300 attendees debated and adopted the 'Declaration of Sentiments' modeled on the Declaration of Independence, asserting that 'all men and women are created equal' and demanding rights including suffrage. Frederick Douglass was among the supporters who helped pass the suffrage resolution." },
  { name:"Compromise of 1850", year:"1850", era:"Antebellum", types:["law","political"], significance:"Temporarily averted Civil War but the Fugitive Slave Act inflamed Northern opinion and radicalized moderates.", desc:"Henry Clay's five-bill package admitted California as a free state, organized New Mexico and Utah territories with popular sovereignty, resolved a Texas boundary dispute, abolished the slave trade in Washington D.C., and — most controversially — enacted a stringent Fugitive Slave Law requiring Northern officials to capture and return escaped slaves. The Fugitive Slave Act drove thousands of Northern moderates toward antislavery politics." },
  { name:"Kansas-Nebraska Act", year:"1854", era:"Antebellum", types:["law","political"], significance:"Destroyed the Missouri Compromise; created 'Bleeding Kansas'; gave birth to the Republican Party.", desc:"Senator Stephen Douglas's bill organized the Kansas and Nebraska territories with 'popular sovereignty' — settlers would vote on whether to allow slavery — effectively repealing the Missouri Compromise's prohibition of slavery above 36°30'. The act outraged Northern opinion, destroyed the Whig Party, gave birth to the Republican Party, and set off violent conflict in Kansas between pro- and antislavery settlers." },
  { name:"Dred Scott Decision", year:"1857", era:"Antebellum", types:["law"], significance:"Ruled that Black Americans could never be citizens; inflamed sectional tensions and accelerated secession.", desc:"Chief Justice Roger Taney's ruling declared that Dred Scott — an enslaved man who had lived in free territories — could not sue for his freedom because Black Americans, whether enslaved or free, were not citizens with legal standing. Taney went further, ruling that Congress had never had the authority to prohibit slavery in any territory, rendering the Missouri Compromise unconstitutional. The decision polarized the nation." },
  { name:"John Brown's Raid on Harper's Ferry", year:"1859", era:"Antebellum", types:["political","social"], significance:"Terrified the South into believing Northern abolitionists would incite slave revolts; accelerated secession movement.", desc:"Radical abolitionist John Brown led 21 men in a raid on the federal arsenal at Harpers Ferry, Virginia, intending to seize weapons and spark a slave rebellion. The raid was quickly suppressed by U.S. Marines under Robert E. Lee. Brown was tried for treason and hanged. His execution made him a martyr in the North and a monster in the South, deepening the chasm that led to Civil War." },
  { name:"Election of 1860", year:"1860", era:"Antebellum", types:["political"], significance:"Lincoln's victory triggered secession; the Democratic Party split between North and South marked the end of compromise.", desc:"Abraham Lincoln won the presidency with only Northern electoral votes, having appeared on no Southern ballot. The Democratic Party had split between Stephen Douglas (North) and John Breckinridge (South). Though Lincoln promised only to prevent slavery's expansion, not to abolish it, his election convinced Southern states that the slave system could no longer be protected within the Union." },
  { name:"Southern Secession", year:"1860–1861", era:"Antebellum", types:["political"], significance:"Led directly to the Civil War; challenged the fundamental question of whether states had the right to leave the Union.", desc:"Following Lincoln's election, South Carolina seceded in December 1860, followed by six more Deep South states before Lincoln's inauguration. They formed the Confederate States of America with Jefferson Davis as president. Four more states joined after the attack on Fort Sumter. The secession crisis tested whether majority rule within a democratic system could be accepted by a minority that disagreed with an election outcome." },

  // ── CIVIL WAR ──
  { name:"Attack on Fort Sumter", year:"1861", era:"Civil War", types:["war"], significance:"Began the Civil War; forced border states to choose sides and energized both sides with patriotic fervor.", desc:"Confederate forces opened fire on the U.S. garrison at Fort Sumter, South Carolina, on April 12, 1861, after the Union refused to evacuate. The 34-hour bombardment forced the fort's surrender without casualties. Lincoln called for 75,000 volunteers to suppress the rebellion, and four more Southern states seceded in response to his call, drawing the lines of the deadliest war in American history." },
  { name:"Emancipation Proclamation", year:"1863", era:"Civil War", types:["political","law"], significance:"Transformed the Civil War into a war for freedom; made European intervention on behalf of the Confederacy politically impossible.", desc:"Issued by Lincoln on January 1, 1863, as a war measure under his commander-in-chief authority, the proclamation declared enslaved people in Confederate states 'forever free.' While it did not immediately free anyone (applying only to rebel states where Lincoln had no authority), it fundamentally transformed the war's meaning, invited Black men to join the Union Army, and made slavery's abolition a war aim that prevented Britain and France from recognizing the Confederacy." },
  { name:"Gettysburg & Vicksburg", year:"1863", era:"Civil War", types:["war"], significance:"Decisive turning point; Confederate defeat eliminated any realistic hope of winning the war.", desc:"In the first week of July 1863, the Confederacy suffered two catastrophic blows: Lee's army was repulsed with devastating losses at Gettysburg, Pennsylvania (July 1–3), ending his second invasion of the North, and Grant captured Vicksburg, Mississippi (July 4), splitting the Confederacy and opening the Mississippi River to Union control. Together, the defeats at Gettysburg and Vicksburg shattered Confederate momentum." },
  { name:"13th Amendment Ratified", year:"1865", era:"Civil War", types:["law","social"], significance:"Permanently abolished slavery throughout the United States, fulfilling the promise of the Emancipation Proclamation.", desc:"The Thirteenth Amendment, passed by Congress in January 1865 and ratified in December, abolished slavery and involuntary servitude throughout the United States except as punishment for crime. It fulfilled the promise of the Emancipation Proclamation by permanently ending the institution that had divided the nation for generations, though the exception clause for criminal punishment would be later used to re-enslave Black Americans through convict leasing." },
  { name:"Assassination of Lincoln", year:"1865", era:"Civil War", types:["political"], significance:"Removed the moderate force from Reconstruction; led to Radical Republican takeover and harsh Reconstruction policies.", desc:"On April 14, 1865, five days after Lee's surrender, Confederate sympathizer and actor John Wilkes Booth shot President Lincoln at Ford's Theatre in Washington D.C. Lincoln died the following morning. The assassination shocked the nation, derailed his magnanimous Reconstruction plan, and brought Vice President Andrew Johnson to power — a disastrous change that empowered the Radical Republicans and deepened sectional conflict." },

  // ── RECONSTRUCTION ──
  { name:"14th Amendment Ratified", year:"1868", era:"Reconstruction", types:["law"], significance:"Guaranteed citizenship and equal protection; became the basis for nearly all 20th-century civil rights law.", desc:"The Fourteenth Amendment granted citizenship to all persons born or naturalized in the United States (overturning Dred Scott), required states to provide equal protection and due process, and reduced congressional representation for states that denied the vote to eligible citizens. Its equal protection and due process clauses became the constitutional foundation for Brown v. Board of Education and virtually all modern civil rights jurisprudence." },
  { name:"15th Amendment Ratified", year:"1870", era:"Reconstruction", types:["law"], significance:"Granted Black men the right to vote; quickly undermined by Southern terror and Northern abandonment.", desc:"The Fifteenth Amendment prohibited denying the right to vote based on 'race, color, or previous condition of servitude.' It enabled brief but significant Black political participation during Reconstruction, including the election of Black senators and congressmen. However, Southern states quickly developed literacy tests, poll taxes, grandfather clauses, and terror campaigns to systematically disenfranchise Black voters — tools that remained effective until the Voting Rights Act of 1965." },
  { name:"Compromise of 1877", year:"1877", era:"Reconstruction", types:["political"], significance:"Ended Reconstruction; withdrew federal troops from the South and enabled the rise of Jim Crow.", desc:"Following the disputed 1876 presidential election between Hayes and Tilden, a congressional compromise awarded the presidency to Republican Hayes in exchange for withdrawing federal troops from the South, effectively ending Reconstruction. Southern Democrats regained control of state governments, dismantled Reconstruction institutions, and erected the Jim Crow system of legal segregation and Black disenfranchisement that would last nearly 90 years." },
  { name:"Civil Rights Act of 1875", year:"1875", era:"Reconstruction", types:["law"], significance:"Struck down by Supreme Court in 1883, opening door to legal segregation and Jim Crow era.", desc:"The last major Reconstruction legislation, it prohibited racial discrimination in public accommodations — hotels, theaters, railroads — and guaranteed Black Americans equal treatment in jury selection. The Supreme Court struck it down in 1883, ruling that Congress could not regulate private conduct under the 14th Amendment, a ruling that opened the legal door to state-mandated segregation." },

  // ── GILDED AGE ──
  { name:"Transcontinental Railroad Completed", year:"1869", era:"Gilded Age", types:["technology","economic"], significance:"United the continent economically; enabled massive westward migration but also enabled final displacement of Plains tribes.", desc:"The joining of the Central Pacific (building east from Sacramento) and the Union Pacific (building west from Omaha) at Promontory Summit, Utah, on May 10, 1869, completed the first transcontinental railroad. The 1,776-mile line was built largely by Chinese and Irish immigrant laborers under brutal conditions. It opened the Great Plains to settlement, enabled the cattle industry, and accelerated the violent displacement of Native peoples." },
  { name:"Battle of Little Bighorn", year:"1876", era:"Gilded Age", types:["war","social"], significance:"Greatest Native American military victory against U.S.; galvanized public support for intensified subjugation of Plains tribes.", desc:"Lieutenant Colonel George Armstrong Custer divided his 7th Cavalry and attacked a massive encampment of Lakota Sioux, Northern Cheyenne, and Arapaho warriors along the Little Bighorn River in Montana. Custer's detachment of approximately 210 men was annihilated. The shocking defeat briefly rallied the nation for military vengeance but ultimately resulted in accelerated campaigns that destroyed the independent Plains tribes within years." },
  { name:"Dawes Act", year:"1887", era:"Gilded Age", types:["law","social"], significance:"Destroyed tribal land ownership; Native Americans lost 90 million of 138 million acres by 1934.", desc:"The Dawes Severalty Act broke up communally-held tribal lands into individual allotments of 160 acres for heads of household, with 'surplus' lands sold to white settlers. Supporters believed private ownership would 'civilize' Native Americans; critics saw it as cultural destruction. Native Americans lost 90 million of 138 million acres over the next 47 years, devastating tribal economies and communities." },
  { name:"Plessy v. Ferguson", year:"1896", era:"Gilded Age", types:["law"], significance:"Established 'separate but equal' doctrine that legalized Jim Crow segregation for 58 years.", desc:"Homer Plessy challenged Louisiana's Separate Car Act requiring racial segregation on railroads. The Supreme Court upheld the law 7-1, ruling that 'separate but equal' facilities satisfied the 14th Amendment's equal protection clause. Justice John Marshall Harlan wrote a famous lone dissent arguing the Constitution is 'color-blind.' The ruling provided the constitutional basis for Jim Crow segregation until Brown v. Board of Education (1954)." },
  { name:"Sherman Antitrust Act", year:"1890", era:"Gilded Age", types:["law","economic"], significance:"First federal law limiting monopolies; used against both corporations AND labor unions initially.", desc:"Congress passed the first federal antitrust law, prohibiting 'every contract, combination, or conspiracy in restraint of trade.' Vaguely worded and initially weakly enforced, it was used more often against labor unions than corporations in its early years. Theodore Roosevelt used it aggressively against railroad and oil trusts; later Supreme Court decisions established the 'rule of reason' limiting its scope." },
  { name:"Homestead Strike", year:"1892", era:"Gilded Age", types:["economic","social"], significance:"Decisive defeat of unionization in the steel industry for 45 years; showed corporations could use private armies against workers.", desc:"Carnegie Steel workers at the Homestead, Pennsylvania mill struck over wage cuts. Carnegie's manager Henry Clay Frick locked out the union and hired 300 Pinkerton detectives to escort strikebreakers. A bloody battle killed 10 men. Pennsylvania's governor sent 8,500 state militia to reopen the plant. The union was crushed, and the steel industry remained non-union until the New Deal." },
  { name:"Pullman Strike", year:"1894", era:"Gilded Age", types:["economic","social","law"], significance:"First time the federal government used an injunction to break a strike; imprisoned Debs and established anti-labor precedent.", desc:"Workers at the Pullman Company, who lived in a company town, struck over wage cuts while rents remained unchanged. Eugene V. Debs's American Railway Union expanded the strike nationally, paralyzing rail traffic. President Cleveland obtained a federal injunction against the strike under the Sherman Antitrust Act and sent in U.S. Army troops over Illinois Governor Altgeld's objection, breaking the strike and imprisoning Debs." },
  { name:"Spanish-American War", year:"1898", era:"Gilded Age", types:["war","foreign"], significance:"Made the U.S. an imperial power with overseas territories; launched American global involvement.", desc:"After the mysterious explosion of the USS Maine in Havana Harbor, inflamed by Hearst and Pulitzer's yellow journalism, the U.S. declared war on Spain. The 'splendid little war' lasted 10 weeks; Spain surrendered Cuba, Puerto Rico, Guam, and the Philippines. The Philippines acquisition sparked a bloody three-year Philippine-American War (1899–1902) and a major debate about whether a democracy could be an empire." },

  // ── PROGRESSIVE ERA ──
  { name:"Triangle Shirtwaist Fire", year:"1911", era:"Progressive Era", types:["social","law"], significance:"Catalyzed sweeping New York labor laws; became a landmark in the history of American labor reform.", desc:"A fire broke out at the Triangle Shirtwaist Factory in New York City; locked exit doors and inadequate fire escapes caused 146 garment workers — mostly young immigrant women — to die in the blaze or jumping from windows. The tragedy galvanized the labor movement and led to 36 new health and safety laws in New York, serving as a national model for workplace safety legislation." },
  { name:"16th & 17th Amendments", year:"1913", era:"Progressive Era", types:["law","political"], significance:"Income tax funded the modern federal government; direct Senate elections removed power from corrupt state legislatures.", desc:"The 16th Amendment authorized a federal income tax, enabling the government to fund Progressive Era social programs and eventually the vast expenditures of WWII and the New Deal. The 17th Amendment provided for direct election of U.S. senators, replacing selection by state legislatures — a key Progressive demand to eliminate the corruption of the Senate by corporate-owned state governments." },
  { name:"Pure Food and Drug Act", year:"1906", era:"Progressive Era", types:["law","social"], significance:"First federal consumer protection law; established precedent for federal regulation of food and medicine.", desc:"Passed in the same year as the Meat Inspection Act, largely in response to Upton Sinclair's 'The Jungle' and years of muckraking journalism, the Pure Food and Drug Act prohibited the manufacture or sale of adulterated or mislabeled food and drugs. It created the federal agency that became the FDA and established the principle that the federal government has a responsibility to protect consumers from harmful products." },
  { name:"World War I U.S. Entry", year:"1917", era:"Progressive Era", types:["war","foreign"], significance:"Transformed the U.S. into a global military power; massive propaganda and draft established precedents for WWII mobilization.", desc:"After years of neutrality, German unrestricted submarine warfare and the Zimmermann Telegram — proposing a German-Mexican alliance against the U.S. — pushed Wilson to ask Congress for a declaration of war in April 1917. The U.S. raised a mass army through the Selective Service Act, launched massive propaganda through the Committee on Public Information, and suppressed dissent through the Espionage and Sedition Acts." },
  { name:"18th Amendment (Prohibition)", year:"1919", era:"Progressive Era", types:["law","social"], significance:"Failed social experiment that strengthened organized crime and undermined respect for law.", desc:"The culmination of decades of temperance activism, Prohibition banned the manufacture and sale of alcoholic beverages. Though consumption did decline, Prohibition also created an enormous illegal market exploited by organized crime figures like Al Capone, undermined respect for law generally, enriched criminal networks, and created a culture of speakeasies. It was repealed by the 21st Amendment in 1933." },
  { name:"19th Amendment (Women's Suffrage)", year:"1920", era:"Progressive Era", types:["law","social"], significance:"Largest single expansion of the electorate in U.S. history; culmination of 72 years of activism.", desc:"The culmination of 72 years of women's suffrage activism beginning at Seneca Falls, the 19th Amendment prohibited denying the right to vote based on sex. Ratified in 1920, it enfranchised approximately 26 million women. The final campaign was led by Carrie Chapman Catt's NAWSA and Alice Paul's more militant National Woman's Party. Tennessee became the deciding 36th state after a 24-year-old legislator voted for ratification after his mother wrote to urge him." },

  // ── NEW DEAL / GREAT DEPRESSION ──
  { name:"Stock Market Crash", year:"1929", era:"New Deal", types:["economic"], significance:"Triggered the Great Depression; exposed dangerous speculation, overextension, and fundamental weaknesses in the economy.", desc:"On October 29, 1929 ('Black Tuesday'), the U.S. stock market collapsed after years of wild speculation, overextension, and buying on margin. The crash itself did not cause the Depression, but it triggered a chain reaction: bank failures, credit contraction, declining investment, layoffs, and falling consumer spending that created a devastating feedback loop. By 1933, unemployment reached 25% and industrial output had fallen by half." },
  { name:"New Deal", year:"1933–1938", era:"New Deal", types:["political","economic","law"], significance:"Permanently expanded the federal government's role in the economy and social welfare; established Social Security.", desc:"FDR's sweeping legislative response to the Depression created dozens of 'alphabet agencies' — the CCC, TVA, WPA, AAA, FDIC, SEC — and landmark legislation including Social Security, the National Labor Relations Act (guaranteeing collective bargaining), and the Fair Labor Standards Act (minimum wage, 40-hour week). While not ending the Depression (WWII did that), the New Deal established the modern welfare state and the expectation that government would manage the economy." },
  { name:"Dust Bowl", year:"1930s", era:"New Deal", types:["social","economic"], significance:"Demonstrated the environmental consequences of unsustainable farming; produced a massive migration that reshaped California.", desc:"A combination of severe drought and decades of intensive farming that removed protective prairie grass from the Great Plains created catastrophic dust storms ('black blizzards') that buried farms and towns across Oklahoma, Texas, Kansas, and Colorado. An estimated 3.5 million people fled the region during the 1930s, with many 'Okies' heading to California, where they faced exploitation and hostility — the human story immortalized in Steinbeck's 'The Grapes of Wrath.'" },
  { name:"Social Security Act", year:"1935", era:"New Deal", types:["law","social"], significance:"Created the first permanent federal safety net; transformed the relationship between citizens and the federal government.", desc:"Frances Perkins's landmark legislation created the Social Security program providing retirement benefits for workers, established unemployment insurance, and provided assistance to children, the blind, and the elderly poor. Initially excluding agricultural and domestic workers (disproportionately Black), it has been expanded many times and today is the largest U.S. government program, fundamentally transforming American ideas about government responsibility." },

  // ── WWII ──
  { name:"Attack on Pearl Harbor", year:"1941", era:"WWII", types:["war","foreign"], significance:"Brought the U.S. into WWII; produced domestic unity and full industrial mobilization.", desc:"On December 7, 1941, Japan launched a surprise attack on the U.S. naval base at Pearl Harbor, Hawaii, killing 2,403 Americans and destroying or damaging 19 Navy ships and 300 aircraft. President Roosevelt called it 'a date which will live in infamy' and asked Congress for a declaration of war. Germany and Italy declared war on the U.S. four days later, bringing the U.S. into both theaters of the global conflict." },
  { name:"Japanese American Internment", year:"1942–1945", era:"WWII", types:["law","social"], significance:"Flagrant violation of civil liberties; Korematsu ruling was cited in modern cases; apology and reparations came in 1988.", desc:"Executive Order 9066 authorized the forced relocation and incarceration of approximately 120,000 Japanese Americans — two-thirds of them U.S. citizens — into internment camps in the western interior. The Supreme Court upheld the order in Korematsu v. United States (1944). In 1988, Congress formally apologized and paid $20,000 in reparations to each surviving internee, acknowledging the action was based on 'racial prejudice, war hysteria, and the failure of political leadership.'" },
  { name:"D-Day (Normandy Invasion)", year:"1944", era:"WWII", types:["war"], significance:"Opened the Western Front; ultimately decisive in defeating Nazi Germany.", desc:"Operation Overlord — the Allied invasion of Normandy, France on June 6, 1944 — was the largest seaborne invasion in history, involving 156,000 troops, 11,000 aircraft, and nearly 7,000 naval vessels. Despite fierce German resistance at Omaha Beach, the Allies established a beachhead that allowed them to liberate France and push into Germany. The invasion is widely considered the turning point of the European war." },
  { name:"Atomic Bombs on Japan", year:"1945", era:"WWII", types:["war","foreign"], significance:"Ended WWII; opened the nuclear age; remains the most debated military decision in American history.", desc:"On August 6 and 9, 1945, the U.S. dropped atomic bombs on Hiroshima and Nagasaki, Japan, killing approximately 110,000–210,000 people immediately and tens of thousands more from radiation. Japan surrendered on August 15, 1945. Truman justified the decision as avoiding an invasion of Japan that military planners estimated would kill hundreds of thousands. Critics argued Japan was already near surrender and the bombs were used partly as a demonstration to the Soviet Union." },

  // ── COLD WAR ──
  { name:"Marshall Plan", year:"1948", era:"Cold War", types:["foreign","economic"], significance:"Rebuilt Western Europe, preventing Communist takeovers; established U.S. leadership of the Western alliance.", desc:"Secretary of State George Marshall proposed a massive program of U.S. economic assistance to rebuild war-devastated Western European economies. Over four years, the U.S. provided approximately $13 billion (about $130 billion in today's dollars) to 16 nations. The program successfully rebuilt European economies, strengthened democratic governments against communist parties, and forged the Atlantic alliance that would persist throughout the Cold War." },
  { name:"Korean War", year:"1950–1953", era:"Cold War", types:["war","foreign"], significance:"First 'limited war' in U.S. history; established that nuclear powers could fight without using nuclear weapons.", desc:"When North Korea invaded South Korea in June 1950, Truman sent U.S. forces under UN authorization to defend the South. After initial UN success, China entered when U.S. forces approached the Yalu River, pushing them back south. The war stalemated roughly along the original 38th parallel; an armistice was signed in 1953 with no formal peace treaty. Over 36,000 Americans died in what critics called 'the forgotten war.'" },
  { name:"Brown v. Board of Education", year:"1954", era:"Cold War", types:["law"], significance:"Overturned Plessy v. Ferguson; desegregated public schools; galvanized the civil rights movement.", desc:"The Supreme Court unanimously ruled that racial segregation in public schools was unconstitutional, overturning the 'separate but equal' doctrine of Plessy v. Ferguson (1896). Chief Justice Warren argued that separate educational facilities were 'inherently unequal.' The decision was followed by 'Brown II' ordering desegregation 'with all deliberate speed' — a vague standard that allowed massive resistance. It remains the most important Supreme Court ruling of the 20th century." },
  { name:"Montgomery Bus Boycott", year:"1955–1956", era:"Cold War", types:["social","civil rights"], significance:"Launched the modern civil rights movement; demonstrated nonviolent direct action could succeed.", desc:"After Rosa Parks's arrest for refusing to give up her bus seat, the Black community of Montgomery, Alabama, organized a 381-day boycott of the city's bus system under the leadership of the newly formed Montgomery Improvement Association and its young president, Dr. Martin Luther King Jr. The boycott, sustained through remarkable community solidarity and carpool networks, ended when the Supreme Court ruled bus segregation unconstitutional." },
  { name:"Civil Rights Act of 1964", year:"1964", era:"Cold War", types:["law","civil rights"], significance:"Most comprehensive civil rights legislation since Reconstruction; outlawed discrimination in public life.", desc:"Passed after JFK's assassination gave LBJ political leverage and massive lobbying by civil rights organizations, the Civil Rights Act of 1964 banned discrimination based on race, color, religion, sex, or national origin in public accommodations (restaurants, hotels, theaters), employment, and federally funded programs. It created the Equal Employment Opportunity Commission (EEOC) and prohibited the use of federal funds for discriminatory programs." },
  { name:"Voting Rights Act of 1965", year:"1965", era:"Cold War", types:["law","civil rights"], significance:"Most effective civil rights law in U.S. history; enabled millions of Black Americans to vote within years.", desc:"Passed following the Selma-to-Montgomery marches and the televised brutality of Bloody Sunday, the Voting Rights Act prohibited discriminatory voting practices including literacy tests and authorized federal oversight of elections in states with a history of discrimination. Within three years, Black voter registration in the South jumped dramatically — Mississippi went from 6.7% to 59.8% Black voter registration." },
  { name:"Cuban Missile Crisis", year:"1962", era:"Cold War", types:["foreign","war"], significance:"Closest the world came to nuclear war; led to direct U.S.-Soviet 'hotline' and partial nuclear test ban treaty.", desc:"When U.S. reconnaissance photographs revealed Soviet nuclear missile installations in Cuba, Kennedy imposed a naval 'quarantine' and demanded removal. For 13 days, the world stood on the edge of nuclear war as Soviet ships approached the blockade. The crisis was resolved when the Soviets agreed to remove missiles in exchange for a U.S. pledge not to invade Cuba and a secret agreement to remove U.S. missiles from Turkey." },
  { name:"Vietnam War (U.S. Involvement)", year:"1964–1975", era:"Cold War", types:["war","foreign"], significance:"Divided American society; discredited Cold War containment doctrine; produced the 'Vietnam Syndrome' of military caution.", desc:"After the Gulf of Tonkin Resolution gave LBJ broad authority to use military force, U.S. involvement escalated from 16,000 advisors to 543,000 troops by 1969. The war cost 58,000 American lives and killed over a million Vietnamese. The Tet Offensive (1968) destroyed public confidence in the war effort. Nixon's 'Vietnamization' policy gradually withdrew troops while secretly expanding the war into Cambodia. Saigon fell to North Vietnamese forces in 1975." },
  { name:"Moon Landing (Apollo 11)", year:"1969", era:"Cold War", types:["technology"], significance:"Greatest technological achievement of the 20th century; fulfilled Kennedy's promise; demonstrated American capability.", desc:"On July 20, 1969, Apollo 11 astronauts Neil Armstrong and Buzz Aldrin became the first humans to walk on the Moon, with Armstrong declaring 'one small step for man, one giant leap for mankind.' The $25 billion program employed 400,000 people and fulfilled Kennedy's 1961 pledge to land a man on the Moon before decade's end. It represented the apex of the Cold War space race with the Soviet Union." },

  // ── MODERN ──
  { name:"Watergate", year:"1972–1974", era:"Modern", types:["political"], significance:"Destroyed public trust in government; led to historic campaign finance and ethics reforms; only presidential resignation in U.S. history.", desc:"A botched burglary at the Democratic National Committee headquarters at the Watergate complex in Washington D.C. unraveled into a constitutional crisis when it emerged that Nixon's Committee to Re-Elect the President had financed the operation and Nixon personally directed the cover-up. The Senate Watergate hearings, the 'Saturday Night Massacre,' and the release of the White House tapes revealed systematic abuse of power. Nixon resigned on August 9, 1974, rather than face certain impeachment and removal." },
  { name:"Roe v. Wade", year:"1973", era:"Modern", types:["law","social"], significance:"Defined reproductive rights; became the most politically divisive Supreme Court ruling; overturned in 2022.", desc:"The Supreme Court ruled 7-2 that the Constitution protected a woman's right to abortion as part of a broader right to privacy, striking down state laws banning abortion. The ruling used a trimester framework to balance women's rights against the state's interest in potential life. Roe became the most politically contested Supreme Court decision of the 20th century, reshaping American politics and ultimately overturned by Dobbs v. Jackson (2022)." },
  { name:"Fall of the Berlin Wall", year:"1989", era:"Modern", types:["foreign","political"], significance:"Symbolized the collapse of European communism and the Cold War's end.", desc:"On November 9, 1989, the East German government announced citizens could cross the Berlin Wall freely. Crowds began dismantling the wall with hammers and pickaxes. The wall had divided East and West Berlin since 1961 and stood as the most powerful symbol of the Iron Curtain. Its fall accelerated German reunification (1990) and the dissolution of the Soviet Union (1991), ending the Cold War that had defined American foreign policy for 45 years." },
  { name:"Fall of the Soviet Union", year:"1991", era:"Modern", types:["foreign","political"], significance:"Ended the Cold War; left the U.S. as the sole global superpower.", desc:"On December 25, 1991, Soviet President Mikhail Gorbachev resigned and the Soviet flag was lowered over the Kremlin for the last time, replaced by the Russian flag. The Soviet Union formally dissolved into 15 independent republics. The Cold War was over. The U.S. found itself the world's sole superpower — a position that raised new questions about America's global role that the foreign policy establishment struggled to answer in the 1990s." },
  { name:"September 11 Attacks", year:"2001", era:"Modern", types:["foreign","war","social"], significance:"Most devastating foreign attack on U.S. soil; launched the 'War on Terror' and transformed American domestic and foreign policy.", desc:"Al-Qaeda terrorists hijacked four commercial aircraft, crashing two into the World Trade Center towers (which collapsed), one into the Pentagon, and one (United Flight 93) into a Pennsylvania field after passengers fought back. 2,977 people died. The attacks led to the invasion of Afghanistan, the Iraq War, the creation of the Department of Homeland Security, the PATRIOT Act's surveillance expansion, and the TSA — reshaping American life, foreign policy, and civil liberties." },
  { name:"Great Recession", year:"2007–2009", era:"Modern", types:["economic"], significance:"Worst financial crisis since the Great Depression; led to massive bank bailouts and permanent debate about financial regulation.", desc:"The collapse of a housing bubble inflated by predatory subprime mortgage lending, securitization of risky loans, and inadequate financial regulation triggered the worst financial crisis since the 1930s. Lehman Brothers collapsed in September 2008 in the largest bankruptcy in U.S. history. Congress passed a $700 billion bank bailout (TARP) and Obama's administration added a $787 billion stimulus. Unemployment peaked at 10%; millions lost their homes." },
  { name:"Affordable Care Act", year:"2010", era:"Modern", types:["law","social"], significance:"Largest expansion of U.S. healthcare coverage since Medicare/Medicaid; insured 20+ million previously uninsured Americans.", desc:"The Patient Protection and Affordable Care Act ('Obamacare') required most Americans to obtain health insurance, expanded Medicaid eligibility, prohibited insurers from denying coverage for pre-existing conditions, allowed children to remain on parents' plans until 26, and created insurance marketplaces. It reduced the uninsured rate from 16% to under 9%. Passed without a single Republican vote, it became the defining political battleground of the Obama years." },
];


